1	/**
2	 * MQTT Configuration API Route
3	 *
4	 * This route handles fetching MQTT configuration for a specific cabinet.
5	 * It supports:
6	 * - Extracting MQTT configuration from machine document
7	 * - Formatting configuration values for display
8	 *
9	 * @module app/api/mqtt/config/route
10	 */
11	
12	import { extractMQTTConfig } from '@/app/api/lib/helpers/mqtt';
13	import { Machine } from '@/app/api/lib/models/machines';
14	import { connectDB } from '@/app/api/lib/middleware/db';
15	import {
16	  logRouteFetch,
17	  logRouteError,
18	  extractUserFromRequest,
19	} from '@/app/api/lib/utils/routeLogger';
20	import { NextRequest, NextResponse } from 'next/server';
21	
22	/**
23	 * Main GET handler for fetching MQTT configuration
24	 *
25	 * @param {string} cabinetId - REQUIRED. Query param: The MongoDB ID of the cabinet
26	 *
27	 * Flow:
28	 * 1. Parse and validate request parameters
29	 * 2. Connect to database
30	 * 3. Find cabinet by ID
31	 * 4. Extract MQTT configuration
32	 * 5. Return MQTT configuration
33	 */
34	export async function GET(request: NextRequest) {
35	  const startTime = Date.now();
36	  const functionName = 'GET /api/mqtt/config';
37	  const user = extractUserFromRequest(request);
38	
39	  try {
40	    // ============================================================================
41	    // STEP 1: Parse and validate request parameters
42	    // ============================================================================
43	    const { searchParams } = new URL(request.url);
44	    const cabinetId = searchParams.get('cabinetId');
45	
46	    if (!cabinetId) {
47	      logRouteError(
48	        functionName,
49	        'GET',
50	        '/api/mqtt/config',
51	        'Cabinet ID is required',
52	        user
53	      );
54	      return NextResponse.json(
55	        { success: false, error: 'Cabinet ID is required' },
56	        { status: 400 }
57	      );
58	    }
59	
60	    // ============================================================================
61	    // STEP 2: Connect to database
62	    // ============================================================================
63	    await connectDB();
64	
65	    // ============================================================================
66	    // STEP 3: Find cabinet by ID
67	    // ============================================================================
68	    const cabinet = await Machine.findOne({ _id: cabinetId });
69	    if (!cabinet) {
70	      logRouteError(
71	        functionName,
72	        'GET',
73	        '/api/mqtt/config',
74	        'Cabinet not found',
75	        user
76	      );
77	      return NextResponse.json(
78	        { success: false, error: 'Cabinet not found' },
79	        { status: 404 }
80	      );
81	    }
82	
83	    // ============================================================================
84	    // STEP 4: Extract MQTT configuration
85	    // ============================================================================
86	    const mqttConfig = extractMQTTConfig(cabinet);
87	
88	    // ============================================================================
89	    // STEP 5: Return MQTT configuration
90	    // ============================================================================
91	    const duration = Date.now() - startTime;
92	    logRouteFetch(functionName, 'GET', '/api/mqtt/config', 1, user, duration);
93	    if (duration > 1000) {
94	      console.warn(`[MQTT Config API] Completed in ${duration}ms`);
95	    }
96	    return NextResponse.json({
97	      success: true,
98	      data: mqttConfig,
99	    });
100	  } catch (error) {
101	    const duration = Date.now() - startTime;
102	    const errorMessage =
103	      error instanceof Error
104	        ? error.message
105	        : 'Failed to fetch MQTT configuration';
106	    logRouteError(functionName, 'GET', '/api/mqtt/config', errorMessage, user);
107	    console.error(
108	      `[MQTT Config GET API] Error after ${duration}ms:`,
109	      errorMessage
110	    );
111	    return NextResponse.json(
112	      { success: false, error: errorMessage },
113	      { status: 500 }
114	    );
115	  }
116	}
