1	/**
2	 * MQTT Config Request API Route
3	 *
4	 * This route handles requesting current configuration from SMIB devices via MQTT.
5	 * It supports:
6	 * - Validating config request body
7	 * - Requesting config from SMIB via MQTT service
8	 * - Note: The callback will be handled by the SSE endpoint
9	 *
10	 * @module app/api/mqtt/config/request/route
11	 */
12	
13	import { validateMQTTConfigRequest } from '@/app/api/lib/helpers/mqtt';
14	import { mqttService } from '@/app/api/lib/services/mqttService';
15	import {
16	  logRouteFetch,
17	  logRouteCreate,
18	  logRouteError,
19	  extractUserFromRequest,
20	} from '@/app/api/lib/utils/routeLogger';
21	import { NextRequest, NextResponse } from 'next/server';
22	
23	/**
24	 * Main POST handler for requesting MQTT config
25	 *
26	 * @body {string} relayId - REQUIRED. The unique relay ID to request from.
27	 * @body {string} component - REQUIRED. The component code to request config for.
28	 *
29	 * Flow:
30	 * 1. Parse request body
31	 * 2. Validate request body
32	 * 3. Request config from SMIB via MQTT
33	 * 4. Return success response
34	 */
35	export async function POST(request: NextRequest) {
36	  const startTime = Date.now();
37	  const functionName = 'POST /api/mqtt/config/request';
38	  const user = extractUserFromRequest(request);
39	
40	  try {
41	    // ============================================================================
42	    // STEP 1: Parse request body
43	    // ============================================================================
44	    const body = await request.json();
45	    const { relayId, component } = body as {
46	      relayId?: string;
47	      component?: string;
48	    };
49	
50	    // ============================================================================
51	    // STEP 2: Validate request body
52	    // ============================================================================
53	    const validationError = validateMQTTConfigRequest(body);
54	    if (validationError) {
55	      logRouteError(
56	        functionName,
57	        'POST',
58	        '/api/mqtt/config/request',
59	        validationError,
60	        user
61	      );
62	      return NextResponse.json(
63	        { success: false, error: validationError },
64	        { status: 400 }
65	      );
66	    }
67	
68	    // ============================================================================
69	    // STEP 3: Request config from SMIB via MQTT
70	    // ============================================================================
71	    await mqttService.requestConfig(relayId!, component!);
72	
73	    // ============================================================================
74	    // STEP 4: Return success response
75	    // ============================================================================
76	    const duration = Date.now() - startTime;
77	    if (duration > 1000) {
78	      console.warn(`[MQTT Config Request API] Completed in ${duration}ms`);
79	    }
80	    logRouteCreate(
81	      functionName,
82	      'POST',
83	      '/api/mqtt/config/request',
84	      1,
85	      user,
86	      duration
87	    );
88	    return NextResponse.json({
89	      success: true,
90	      message: `Config request sent for ${component} to relayId: ${relayId}`,
91	      relayId,
92	      component,
93	      timestamp: new Date().toISOString(),
94	    });
95	  } catch (error) {
96	    const duration = Date.now() - startTime;
97	    const errorMessage =
98	      error instanceof Error ? error.message : 'Unknown error';
99	    logRouteError(
100	      functionName,
101	      'POST',
102	      '/api/mqtt/config/request',
103	      errorMessage,
104	      user
105	    );
106	    console.error(
107	      `[MQTT Config Request API] Error after ${duration}ms:`,
108	      errorMessage
109	    );
110	    return NextResponse.json(
111	      {
112	        success: false,
113	        error: errorMessage,
114	        timestamp: new Date().toISOString(),
115	      },
116	      { status: 500 }
117	    );
118	  }
119	}
