121	/**
122	 * GET /api/mqtt/config/request
123	 * Get information about the request endpoint
124	 */
125	export async function GET(request: NextRequest) {
126	  const startTime = Date.now();
127	  const functionName = 'GET /api/mqtt/config/request';
128	  const user = extractUserFromRequest(request);
129	
130	  const duration = Date.now() - startTime;
131	  logRouteFetch(
132	    functionName,
133	    'GET',
134	    '/api/mqtt/config/request',
135	    1,
136	    user,
137	    duration
138	  );
139	  return NextResponse.json({
140	    success: true,
141	    message: 'MQTT Config Request API',
142	    usage: {
143	      request:
144	        'POST /api/mqtt/config/request with { "relayId": "string", "component": "string" }',
145	      components: ['mqtt', 'ota', 'coms', 'net', 'app'],
