1	/**
2	 * MQTT Config Subscribe API Route (SSE)
3	 *
4	 * This route handles Server-Sent Events (SSE) for live MQTT config updates.
5	 * It supports:
6	 * - GET: Establishes an SSE connection for real-time MQTT config updates for a specific `relayId`
7	 *
8	 * @module app/api/mqtt/config/subscribe/route
9	 */
10	
11	import { mqttService } from '@/app/api/lib/services/mqttService';
12	import {
13	  logRouteFetch,
14	  logRouteError,
15	  extractUserFromRequest,
16	} from '@/app/api/lib/utils/routeLogger';
17	import { NextRequest } from 'next/server';
18	
19	/**
20	 * Main GET handler for MQTT config SSE subscription
21	 *
22	 * @param {string} relayId - REQUIRED. The unique relay ID to subscribe to updates for.
23	 *
24	 * Flow:
25	 * 1. Parse and validate relayId parameter
26	 * 2. Set up SSE headers
27	 * 3. Create readable stream for SSE
28	 * 4. Register MQTT callback for config updates
29	 * 5. Handle client disconnect and cleanup
30	 * 6. Return SSE response stream
31	 */
32	export async function GET(request: NextRequest) {
33	  const startTime = Date.now();
34	  const functionName = 'GET /api/mqtt/config/subscribe';
35	  const user = extractUserFromRequest(request);
36	
37	  try {
38	    // ============================================================================
39	    // STEP 1: Parse and validate relayId parameter
40	    // ============================================================================
41	    const { searchParams } = new URL(request.url);
42	    const relayId = searchParams.get('relayId');
43	
44	    if (!relayId) {
45	      const duration = Date.now() - startTime;
46	      logRouteError(
47	        functionName,
48	        'GET',
49	        '/api/mqtt/config/subscribe',
50	        'relayId query parameter is required',
51	        user
52	      );
53	      console.error(
54	        `[MQTT Config Subscribe GET API] Missing relayId parameter after ${duration}ms.`
55	      );
56	      return new Response(
57	        JSON.stringify({ error: 'relayId query parameter is required' }),
58	        {
59	          status: 400,
60	          headers: { 'Content-Type': 'application/json' },
61	        }
62	      );
63	    }
64	
65	    console.log(
66	      `[MQTT Config Subscribe GET API] Establishing SSE connection for relayId: ${relayId}`
67	    );
68	
69	    // ============================================================================
70	    // STEP 2: Set up SSE headers
71	    // ============================================================================
72	    const headers = new Headers({
73	      'Content-Type': 'text/event-stream',
74	      'Cache-Control': 'no-cache',
75	      Connection: 'keep-alive',
76	      'Access-Control-Allow-Origin': '*',
77	      'Access-Control-Allow-Headers': 'Cache-Control',
78	    });
79	
80	    // ============================================================================
81	    // STEP 3: Create readable stream for SSE
82	    // ============================================================================
83	    const stream = new ReadableStream({
84	      start(controller) {
85	        // ============================================================================
86	        // STEP 3a: Send initial connection message
87	        // ============================================================================
88	        const initialMessage = {
89	          type: 'connected',
90	          relayId,
91	          timestamp: new Date().toISOString(),
92	          message: 'Connected to MQTT config stream',
93	        };
94	        controller.enqueue(`data: ${JSON.stringify(initialMessage)}\n\n`);
95	
96	        // ============================================================================
97	        // STEP 3b: Track connection state
98	        // ============================================================================
99	        let isClosed = false;
100	
101	        // ============================================================================
102	        // STEP 4: Register MQTT callback for config updates
103	        // ============================================================================
104	        const handleConfigMessage = (message: Record<string, unknown>) => {
105	          if (isClosed) {
106	            return;
107	          }
108	
109	          const messageType = (message.typ as string) || 'unknown';
110	          const messageRelayId = (message.rly as string) || relayId;
111	
112	          // Only log meter responses with errors
113	          if (messageType === 'rsp' && message.pyd === '-1') {
114	            console.warn(
115	              `[MQTT Config Subscribe GET API] SMIB ${messageRelayId} returned error: -1`
116	            );
117	          }
118	
119	          const sseMessage = {
120	            type: 'config_update',
121	            relayId: messageRelayId,
122	            component: message.comp,
123	            data: message,
124	            timestamp: new Date().toISOString(),
125	          };
126	
127	          try {
128	            controller.enqueue(`data: ${JSON.stringify(sseMessage)}\n\n`);
129	          } catch (enqueueError) {
130	            console.error(
131	              `[MQTT Config Subscribe GET API] Failed to enqueue message:`,
132	              enqueueError
133	            );
134	          }
135	        };
136	
137	        // Subscribe to config updates
138	        mqttService
139	          .subscribeToConfig(relayId, handleConfigMessage)
140	          .then(() => {
141	            const callbackReadyMessage = {
142	              type: 'callback_ready',
143	              relayId,
144	              timestamp: new Date().toISOString(),
145	              message: 'Callback registered and ready for meter requests',
146	            };
147	            controller.enqueue(
148	              `data: ${JSON.stringify(callbackReadyMessage)}\n\n`
149	            );
150	          })
151	          .catch(error => {
152	            console.error(
153	              `[MQTT Config Subscribe GET API] Failed to subscribe to config for relayId ${relayId}:`,
154	              error
155	            );
156	            const errorMessage = {
157	              type: 'error',
158	              relayId,
159	              error: error instanceof Error ? error.message : 'Unknown error',
160	              timestamp: new Date().toISOString(),
161	            };
162	            controller.enqueue(`data: ${JSON.stringify(errorMessage)}\n\n`);
163	          });
164	
165	        // ============================================================================
166	        // STEP 5: Handle client disconnect and cleanup
167	        // ============================================================================
168	        const handleDisconnect = () => {
169	          console.log(
170	            `[MQTT Config Subscribe GET API] Client disconnected for relayId: ${relayId}`
171	          );
172	          isClosed = true;
173	          mqttService.unsubscribeCallback(relayId, handleConfigMessage);
174	          try {
175	            controller.close();
176	          } catch (closeError) {
177	            // Controller might already be closed
178	            console.log(
179	              `[MQTT Config Subscribe GET API] Controller already closed:`,
180	              closeError
181	            );
182	          }
183	        };
184	
185	        request.signal.addEventListener('abort', handleDisconnect);
186	
187	        // Send keep-alive/heartbeat messages every 5 seconds
188	        const keepAliveInterval = setInterval(() => {
189	          if (request.signal.aborted || isClosed) {
190	            clearInterval(keepAliveInterval);
191	            return;
192	          }
193	
194	          const keepAliveMessage = {
195	            type: 'heartbeat',
196	            relayId,
197	            timestamp: new Date().toISOString(),
198	          };
199	
200	          try {
201	            controller.enqueue(`data: ${JSON.stringify(keepAliveMessage)}\n\n`);
202	          } catch (error) {
203	            console.error(
204	              `[MQTT Config Subscribe GET API] Error sending keep-alive:`,
205	              error
206	            );
207	            isClosed = true;
208	            clearInterval(keepAliveInterval);
209	          }
210	        }, 5000);
211	
212	        // Clean up interval on abort
213	        request.signal.addEventListener('abort', () => {
214	          isClosed = true;
215	          clearInterval(keepAliveInterval);
216	        });
217	      },
218	      cancel() {
219	        console.log(
220	          `[MQTT Config Subscribe GET API] SSE stream cancelled for relayId: ${relayId}`
221	        );
222	        // Fallback cleanup when stream is cancelled
223	        mqttService.unsubscribeFromConfig(relayId);
224	      },
225	    });
226	
227	    // ============================================================================
228	    // STEP 6: Return SSE response stream
229	    // ============================================================================
230	    const duration = Date.now() - startTime;
231	    logRouteFetch(
232	      functionName,
233	      'GET',
234	      '/api/mqtt/config/subscribe',
235	      1,
236	      user,
237	      duration
238	    );
239	    console.log(
240	      `[MQTT Config Subscribe GET API] SSE connection established for relayId: ${relayId} after ${duration}ms.`
241	    );
242	    return new Response(stream, { headers });
243	  } catch (error) {
244	    const duration = Date.now() - startTime;
245	    const errorMessage =
246	      error instanceof Error ? error.message : 'Internal server error';
247	    logRouteError(
248	      functionName,
249	      'GET',
250	      '/api/mqtt/config/subscribe',
251	      errorMessage,
252	      user
253	    );
254	    console.error(
255	      `[MQTT Config Subscribe GET API] Error after ${duration}ms:`,
256	      errorMessage
257	    );
258	    return new Response(
259	      JSON.stringify({ error: 'Failed to establish SSE connection' }),
260	      {
261	        status: 500,
262	        headers: { 'Content-Type': 'application/json' },
263	      }
264	    );
265	  }
266	}
