1	/**
2	 * Update Machine Config API Route
3	 *
4	 * This route handles updating machine SMIB configuration by relayId.
5	 * It supports:
6	 * - Finding machine by relayId
7	 * - Updating SMIB configuration and version
8	 * - Activity logging
9	 *
10	 * @module app/api/mqtt/update-machine-config/route
11	 */
12	
13	import {
14	  calculateChanges,
15	  logActivity,
16	} from '@/app/api/lib/helpers/activityLogger';
17	import {
18	  buildMachineConfigUpdateFields,
19	  findMachineByRelayId,
20	  getLocationName,
21	  updateMachineConfiguration,
22	} from '@/app/api/lib/helpers/machineConfig';
23	import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
24	import { connectDB } from '@/app/api/lib/middleware/db';
25	import { getClientIP } from '@/lib/utils/ipAddress';
26	import {
27	  logRouteError,
28	  logRouteUpdate,
29	  extractUserFromRequest,
30	} from '@/app/api/lib/utils/routeLogger';
31	import { NextRequest, NextResponse } from 'next/server';
32	
33	/**
34	 * Main POST handler for updating machine configuration
35	 *
36	 * @body {string} relayId - REQUIRED. The unique relay ID of the machine.
37	 * @body {Object} smibConfig - REQUIRED. The new SMIB configuration object.
38	 * @body {string} smibVersion - Optional. The new SMIB firmware version.
39	 *
40	 * Flow:
41	 * 1. Parse and validate request body
42	 * 2. Connect to database
43	 * 3. Find machine by relayId
44	 * 4. Get location for logging
45	 * 5. Build update fields
46	 * 6. Update machine configuration
47	 * 7. Log activity
48	 * 8. Return success response
49	 */
50	export async function POST(request: NextRequest) {
51	  const startTime = Date.now();
52	  const functionName = 'POST /api/mqtt/update-machine-config';
53	  const user = extractUserFromRequest(request);
54	
55	  try {
56	    // ============================================================================
57	    // STEP 1: Parse and validate request body
58	    // ============================================================================
59	    const body = await request.json();
60	    const { relayId, smibConfig, smibVersion } = body as {
61	      relayId?: string;
62	      smibConfig?: Record<string, unknown>;
63	      smibVersion?: Record<string, unknown>;
64	    };
65	
66	    if (!relayId) {
67	      return NextResponse.json(
68	        { success: false, error: 'relayId is required' },
69	        { status: 400 }
70	      );
71	    }
72	
73	    // ============================================================================
74	    // STEP 2: Connect to database
75	    // ============================================================================
76	    await connectDB();
77	
78	    // ============================================================================
79	    // STEP 3: Find machine by relayId
80	    // ============================================================================
81	    const machine = await findMachineByRelayId(relayId);
82	    if (!machine) {
83	      return NextResponse.json(
84	        { success: false, error: 'Machine not found with this relayId' },
85	        { status: 404 }
86	      );
87	    }
88	
89	    // Type assertion for machine document
90	    const machineDoc = machine as Awaited<
91	      ReturnType<typeof findMachineByRelayId>
92	    > & {
93	      gamingLocation?: unknown;
94	      _id: { toString: () => string };
95	      serialNumber?: string;
96	      game?: string;
97	      smibConfig?: Record<string, unknown>;
98	      smibVersion?: Record<string, unknown>;
99	      toObject?: () => Record<string, unknown>;
100	    };
101	
102	    // ============================================================================
103	    // STEP 4: Get location for logging
104	    // ============================================================================
105	    const locationName = await getLocationName(machineDoc.gamingLocation);
106	
107	    // ============================================================================
108	    // STEP 5: Build update fields
109	    // ============================================================================
110	    const originalMachine = machineDoc.toObject
111	      ? machineDoc.toObject()
112	      : JSON.parse(JSON.stringify(machineDoc));
113	    const updateFields = buildMachineConfigUpdateFields(
114	      machineDoc,
115	      smibConfig,
116	      smibVersion
117	    );
118	
119	    // ============================================================================
120	    // STEP 6: Update machine configuration
121	    // ============================================================================
122	    const updatedMachine = await updateMachineConfiguration(
123	      machineDoc._id.toString(),
124	      updateFields
125	    );
126	
127	    if (!updatedMachine) {
128	      return NextResponse.json(
129	        { success: false, error: 'Failed to update machine' },
130	        { status: 500 }
131	      );
132	    }
133	
134	    // ============================================================================
135	    // STEP 7: Log activity
136	    // ============================================================================
137	    const currentUser = await getUserFromServer();
138	    if (currentUser && currentUser.emailAddress) {
139	      try {
140	        const changes = calculateChanges(originalMachine, updateFields);
141	
142	        await logActivity({
143	          action: 'UPDATE',
144	          details: `Updated SMIB configuration for machine "${
145	            machineDoc.serialNumber || machineDoc.game || 'Unknown'
146	          }" (relayId: ${relayId})${
147	            locationName ? ` in location "${locationName}"` : ''
148	          }`,
149	          ipAddress: getClientIP(request) || undefined,
150	          userAgent: request.headers.get('user-agent') || undefined,
151	          metadata: {
152	            userId: currentUser._id as string,
153	            userEmail: currentUser.emailAddress as string,
154	            userRole: (currentUser.roles as string[])?.[0] || 'user',
155	            resource: 'machine',
156	            resourceId: machineDoc._id.toString(),
157	            resourceName:
158	              machineDoc.serialNumber || machineDoc.game || 'Unknown',
159	            relayId,
160	            changes,
161	            source: 'smib-management-tab',
162	          },
163	        });
164	      } catch (logError) {
165	        console.error('Failed to log activity:', logError);
166	      }
167	    }
168	
169	    // ============================================================================
170	    // STEP 8: Return success response
171	    // ============================================================================
172	    const duration = Date.now() - startTime;
173	    logRouteUpdate(
174	      functionName,
175	      'POST',
176	      '/api/mqtt/update-machine-config',
177	      1,
178	      user,
179	      duration
180	    );
181	
182	    return NextResponse.json({
183	      success: true,
184	      data: updatedMachine,
185	      machineId: updatedMachine
186	        ? (updatedMachine as { _id: { toString: () => string } })._id.toString()
187	        : machineDoc._id.toString(),
188	    });
189	  } catch (error) {
190	    const errorMessage =
191	      error instanceof Error ? error.message : 'Unknown error';
192	    logRouteError(
193	      functionName,
194	      'POST',
195	      '/api/mqtt/update-machine-config',
196	      errorMessage,
197	      user
198	    );
199	    return NextResponse.json(
200	      {
201	        success: false,
202	        error: errorMessage,
203	      },
204	      { status: 500 }
205	    );
206	  }
207	}
