1	/**
2	 * SMIB Meters API Route
3	 *
4	 * This route handles requesting meter data from a single SMIB device.
5	 * It supports:
6	 * - Requesting meters by relayId
7	 * - Finding machine by relayId
8	 * - Sending meter request via MQTT
9	 * - Activity logging
10	 *
11	 * Note: Uses POST instead of GET because:
12	 * - We're sending a command/action to the SMIB (triggering it to read meters)
13	 * - This modifies state (SMIB performs a meter read operation)
14	 * - Not idempotent (each request triggers a new meter read)
15	 * - Requires request body (relayId) which is more RESTful as POST
16	 * - The response comes via MQTT/SSE, not as the HTTP response
17	 *
18	 * @module app/api/smib/meters/route
19	 */
20	
21	import { logActivity } from '@/app/api/lib/helpers/activityLogger';
22	import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
23	import { connectDB } from '@/app/api/lib/middleware/db';
24	import { Machine } from '@/app/api/lib/models/machines';
25	import { mqttService } from '@/app/api/lib/services/mqttService';
26	import {
27	  logRouteCreate,
28	  logRouteError,
29	  extractUserFromRequest,
30	} from '@/app/api/lib/utils/routeLogger';
31	import { getClientIP } from '@/lib/utils/ipAddress';
32	import { NextRequest, NextResponse } from 'next/server';
33	
34	/**
35	 * Main POST handler for requesting SMIB meters
36	 *
37	 * @body {string} relayId - REQUIRED. The unique relay ID of the machine to read meters from.
38	 *
39	 * Flow:
40	 * 1. Parse request body
41	 * 2. Validate relayId
42	 * 3. Connect to database
43	 * 4. Find machine by relayId
44	 * 5. Check for MQTT callbacks
45	 * 6. Authenticate user
46	 * 7. Send meter request via MQTT
47	 * 8. Log activity
48	 * 9. Return success response
49	 */
50	export async function POST(request: NextRequest) {
51	  const startTime = Date.now();
52	  const functionName = 'POST /api/smib/meters';
53	  const user = extractUserFromRequest(request);
54	
55	  try {
56	    // ============================================================================
57	    // STEP 1: Parse request body
58	    // ============================================================================
59	    const { relayId } = await request.json();
60	
61	    // ============================================================================
62	    // STEP 2: Validate relayId
63	    // ============================================================================
64	
65	    if (!relayId) {
66	      return NextResponse.json(
67	        { success: false, error: 'RelayId is required' },
68	        { status: 400 }
69	      );
70	    }
71	
72	    // ============================================================================
73	    // STEP 3: Connect to database
74	    // ============================================================================
75	    await connectDB();
76	
77	    // ============================================================================
78	    // STEP 4: Find machine by relayId
79	    // ============================================================================
80	    const machine = await Machine.findOne({
81	      $or: [{ relayId }, { smibBoard: relayId }],
82	    });
83	
84	    if (!machine) {
85	      return NextResponse.json(
86	        { success: false, error: 'Machine not found for this relayId' },
87	        { status: 404 }
88	      );
89	    }
90	
91	    // ============================================================================
92	    // STEP 5: Check for MQTT callbacks
93	    // ============================================================================
94	    const hasCallbacks = mqttService.hasCallbacksForRelayId(relayId);
95	
96	    if (!hasCallbacks) {
97	      console.warn(
98	        `No callbacks registered for relayId ${relayId} - response may be lost`
99	      );
100	    }
101	
102	    // ============================================================================
103	    // STEP 6: Authenticate user
104	    // ============================================================================
105	    const currentUser = await getUserFromServer();
106	    if (!currentUser || !currentUser._id || !currentUser.emailAddress) {
107	      return NextResponse.json(
108	        { success: false, error: 'Authentication required to request meters' },
109	        { status: 401 }
110	      );
111	    }
112	
113	    // ============================================================================
114	    // STEP 7: Send meter request via MQTT
115	    // ============================================================================
116	    try {
117	      await mqttService.requestMeterData(relayId);
118	    } catch {
119	      return NextResponse.json(
120	        {
121	          success: false,
122	          error: 'Failed to send meter request to SMIB',
123	        },
124	        { status: 500 }
125	      );
126	    }
127	
128	    // ============================================================================
129	    // STEP 8: Log activity
130	    // ============================================================================
131	    const clientIP = getClientIP(request);
132	    try {
133	      await logActivity({
134	        action: 'VIEW',
135	        details: `Meter data requested from SMIB ${relayId} for machine ${machine.serialNumber || machine._id}`,
136	        ipAddress: clientIP || undefined,
137	        userAgent: request.headers.get('user-agent') || undefined,
138	        userId: currentUser._id as string,
139	        username: currentUser.username as string,
140	        metadata: {
141	          userRole: (currentUser.roles as string[])?.[0] || 'user',
142	          resource: 'machine',
143	          resourceId: machine._id.toString(),
144	          resourceName: machine.serialNumber || machine.game || machine._id,
145	          relayId,
146	          requestedAt: new Date().toISOString(),
147	        },
148	      });
149	    } catch (logError) {
150	      console.error('Failed to log activity:', logError);
151	    }
152	
153	    // ============================================================================
154	    // STEP9: Return success response
155	    // ============================================================================
156	    const duration = Date.now() - startTime;
157	    logRouteCreate(functionName, 'POST', '/api/smib/meters', 1, user, duration);
158	
159	    if (duration > 1000) {
160	      console.warn(`[SMIB Meters API] Completed in ${duration}ms`);
161	    }
162	    return NextResponse.json({
163	      success: true,
164	      message: 'Meter request sent successfully',
165	      relayId,
166	    });
167	  } catch (error) {
168	    const duration = Date.now() - startTime;
169	    const errorMessage =
170	      error instanceof Error ? error.message : 'Internal server error';
171	    logRouteError(functionName, 'POST', '/api/smib/meters', errorMessage, user);
172	    console.error(`[SMIB Meters API] Error after ${duration}ms:`, errorMessage);
173	    return NextResponse.json(
174	      { success: false, error: errorMessage },
175	      { status: 500 }
176	    );
177	  }
178	}
