1	/**
2	 * SMIB NVS Action API Route
3	 *
4	 * This route handles executing NVS clear actions on SAS SMIB devices.
5	 * It supports:
6	 * - clear_nvs: Clear all NVS
7	 * - clear_nvs_meters: Clear NVS meters
8	 * - clear_nvs_bv: Clear NVS bill validator
9	 * - clear_nvs_door: Clear NVS door
10	 * - Sending commands via MQTT
11	 * - Activity logging
12	 *
13	 * @module app/api/smib/nvs-action/route
14	 */
15	
16	import { logActivity } from '@/app/api/lib/helpers/activityLogger';
17	import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
18	import { connectDB } from '@/app/api/lib/middleware/db';
19	import { mqttService } from '@/app/api/lib/services/mqttService';
20	import {
21	  logRouteCreate,
22	  logRouteError,
23	  extractUserFromRequest,
24	} from '@/app/api/lib/utils/routeLogger';
25	import { getClientIP } from '@/lib/utils/ipAddress';
26	import { NextRequest, NextResponse } from 'next/server';
27	
28	/**
29	 * Main POST handler for executing NVS actions
30	 *
31	 * @body {string} relayId - REQUIRED. The unique relay ID of the target SMIB.
32	 * @body {string} action - REQUIRED. The NVS clear action ('clear_nvs', 'clear_nvs_meters', etc.).
33	 *
34	 * Flow:
35	 * 1. Parse request body
36	 * 2. Validate relayId and action
37	 * 3. Connect to database
38	 * 4. Send appropriate NVS command via MQTT
39	 * 5. Log activity
40	 * 6. Return success response
41	 */
42	export async function POST(request: NextRequest) {
43	  const startTime = Date.now();
44	  const functionName = 'POST /api/smib/nvs-action';
45	  const user = extractUserFromRequest(request);
46	
47	  try {
48	    // ============================================================================
49	    // STEP 1: Parse request body
50	    // ============================================================================
51	    const { relayId, action } = await request.json();
52	
53	    // ============================================================================
54	    // STEP 2: Validate relayId and action
55	    // ============================================================================
56	
57	    if (!relayId) {
58	      return NextResponse.json(
59	        { success: false, error: 'RelayId is required' },
60	        { status: 400 }
61	      );
62	    }
63	
64	    if (!action) {
65	      return NextResponse.json(
66	        { success: false, error: 'Action is required' },
67	        { status: 400 }
68	      );
69	    }
70	
71	    const validActions = [
72	      'clear_nvs',
73	      'clear_nvs_meters',
74	      'clear_nvs_bv',
75	      'clear_nvs_door',
76	    ];
77	    if (!validActions.includes(action)) {
78	      return NextResponse.json(
79	        {
80	          success: false,
81	          error: `Invalid action. Must be one of: ${validActions.join(', ')}`,
82	        },
83	        { status: 400 }
84	      );
85	    }
86	
87	    // ============================================================================
88	    // STEP 3: Connect to database
89	    // ============================================================================
90	    await connectDB();
91	
92	    // ============================================================================
93	    // STEP 4: Send appropriate NVS command via MQTT
94	    // ============================================================================
95	    try {
96	      switch (action) {
97	        case 'clear_nvs':
98	          await mqttService.sendClearNvs(relayId);
99	          break;
100	        case 'clear_nvs_meters':
101	          await mqttService.sendClearNvsMeters(relayId);
102	          break;
103	        case 'clear_nvs_bv':
104	          await mqttService.sendClearNvsBv(relayId);
105	          break;
106	        case 'clear_nvs_door':
107	          await mqttService.sendClearNvsDoor(relayId);
108	          break;
109	        default:
110	          throw new Error(`Unhandled action: ${action}`);
111	      }
112	    } catch {
113	      return NextResponse.json(
114	        {
115	          success: false,
116	          error: `Failed to send ${action} command to SMIB`,
117	        },
118	        { status: 500 }
119	      );
120	    }
121	
122	    // ============================================================================
123	    // STEP 5: Log activity
124	    // ============================================================================
125	    const currentUser = await getUserFromServer();
126	    const clientIP = getClientIP(request);
127	
128	    if (currentUser && currentUser.emailAddress) {
129	      try {
130	        await logActivity({
131	          userId: currentUser._id as string,
132	          username: currentUser.emailAddress as string,
133	          action: 'update',
134	          details: `${action} command sent to SMIB ${relayId}`,
135	          ipAddress: clientIP || undefined,
136	          userAgent: request.headers.get('user-agent') || undefined,
137	          metadata: {
138	            resource: 'machine',
139	            resourceId: relayId,
140	            resourceName: relayId,
141	            userEmail: currentUser.emailAddress as string,
142	            userRole: (currentUser.roles as string[])?.[0] || 'user',
143	            relayId,
144	            nvsAction: action,
145	            executedAt: new Date().toISOString(),
146	          },
147	        });
148	      } catch (logError) {
149	        console.error('Failed to log activity:', logError);
150	      }
151	    }
152	
153	    // ============================================================================
154	    // STEP6: Return success response
155	    // ============================================================================
156	    const duration = Date.now() - startTime;
157	    logRouteCreate(
158	      functionName,
159	      'POST',
160	      '/api/smib/nvs-action',
161	      1,
162	      user,
163	      duration
164	    );
165	
166	    if (duration > 1000) {
167	      console.warn(`[SMIB NVS Action API] Completed in ${duration}ms`);
168	    }
169	    return NextResponse.json({
170	      success: true,
171	      message: `${action} command sent successfully`,
172	      relayId,
173	      action,
174	    });
175	  } catch (error) {
176	    const duration = Date.now() - startTime;
177	    const errorMessage =
178	      error instanceof Error ? error.message : 'Internal server error';
179	    logRouteError(
180	      functionName,
181	      'POST',
182	      '/api/smib/nvs-action',
183	      errorMessage,
184	      user
185	    );
186	    console.error(
187	      `[SMIB NVS Action API] Error after ${duration}ms:`,
188	      errorMessage
189	    );
190	    return NextResponse.json(
191	      { success: false, error: errorMessage },
192	      { status: 500 }
193	    );
194	  }
195	}
