1	/**
2	 * SMIB OTA Update API Route
3	 *
4	 * This route handles triggering OTA firmware updates for a single SMIB device.
5	 * It supports:
6	 * - Preparing firmware file from GridFS
7	 * - Building firmware URL from request headers
8	 * - Configuring OTA URL on SMIB
9	 * - Sending OTA update command via MQTT
10	 * - Updating firmwareUpdatedAt timestamp
11	 * - Activity logging
12	 *
13	 * @module app/api/smib/ota-update/route
14	 */
15	
16	import { logActivity } from '@/app/api/lib/helpers/activityLogger';
17	import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
18	import { connectDB } from '@/app/api/lib/middleware/db';
19	import { Machine } from '@/app/api/lib/models/machines';
20	import { mqttService } from '@/app/api/lib/services/mqttService';
21	import {
22	  logRouteCreate,
23	  logRouteError,
24	  extractUserFromRequest,
25	} from '@/app/api/lib/utils/routeLogger';
26	import { getClientIP } from '@/lib/utils/ipAddress';
27	import axios from 'axios';
28	import { NextRequest, NextResponse } from 'next/server';
29	
30	/**
31	 * @param {string} relayId - REQUIRED. The unique identifier of the SMIB board (via body)
32	 * @param {string} firmwareId - REQUIRED. The MongoDB ID of the firmware to install (via body)
33	 *
34	 * @body {string} relayId - REQUIRED. SMIB identifier
35	 * @body {string} firmwareId - REQUIRED. Firmware record ID
36	 *
37	 * Flow:
38	 * 1. Parse request body
39	 * 2. Validate relayId and firmwareId
40	 * 3. Connect to database
41	 * 4. Prepare firmware file and get URL
42	 * 5. Build firmware URL from request headers
43	 * 6. Configure OTA URL on SMIB
44	 * 7. Send OTA update command
45	 * 8. Update firmwareUpdatedAt timestamp
46	 * 9. Log activity
47	 * 10. Return success response
48	 */
49	export async function POST(request: NextRequest) {
50	  const startTime = Date.now();
51	  const functionName = 'POST /api/smib/ota-update';
52	  const user = extractUserFromRequest(request);
53	
54	  try {
55	    // ============================================================================
56	    // STEP 1: Parse request body
57	    // ============================================================================
58	    const { relayId, firmwareId } = await request.json();
59	
60	    // ============================================================================
61	    // STEP 2: Validate relayId and firmwareId
62	    // ============================================================================
63	
64	    if (!relayId || !firmwareId) {
65	      return NextResponse.json(
66	        {
67	          success: false,
68	          error: 'RelayId and firmwareId are required',
69	        },
70	        { status: 400 }
71	      );
72	    }
73	
74	    // ============================================================================
75	    // STEP 3: Connect to database
76	    // ============================================================================
77	    await connectDB();
78	
79	    // ============================================================================
80	    // STEP 4: Prepare firmware file and get URL
81	    // ============================================================================
82	    const serveResponse = await axios.get(
83	      `${request.headers.get('origin') || 'http://localhost:3000'}/api/firmwares/${firmwareId}/serve`
84	    );
85	
86	    if (!serveResponse.data.success) {
87	      return NextResponse.json(
88	        { success: false, error: 'Failed to prepare firmware file' },
89	        { status: 500 }
90	      );
91	    }
92	
93	    const { fileName } = serveResponse.data;
94	
95	    // ============================================================================
96	    // STEP 5: Build firmware URL from request headers
97	    // ============================================================================
98	    let host = request.headers.get('host');
99	    const protocol = request.headers.get('x-forwarded-proto') || 'http';
100	
101	    // If host is localhost, try to get the actual network IP
102	    if (host?.includes('localhost') || host?.includes('127.0.0.1')) {
103	      const forwardedHost = request.headers.get('x-forwarded-host');
104	      if (forwardedHost && !forwardedHost.includes('localhost')) {
105	        host = forwardedHost;
106	      } else {
107	        const networkIp = process.env.NETWORK_IP;
108	        if (networkIp) {
109	          host = `${networkIp}:3000`;
110	        }
111	      }
112	    }
113	
114	    const baseUrl = `${protocol}://${host}`;
115	    const firmwareBinUrl = `${baseUrl}/firmwares/`;
116	
117	    // ============================================================================
118	    // STEP 6: Configure OTA URL on SMIB
119	    // ============================================================================
120	    try {
121	      await mqttService.configureOTAUrl(relayId, firmwareBinUrl);
122	
123	      // Wait for config to be applied
124	      await new Promise(resolve => setTimeout(resolve, 1000));
125	
126	      // ============================================================================
127	      // STEP 7: Send OTA update command
128	      // ============================================================================
129	      await mqttService.sendOTAUpdateCommand(relayId, firmwareBinUrl);
130	
131	      // ============================================================================
132	      // STEP 8: Update firmwareUpdatedAt timestamp
133	      // ============================================================================
134	      const updateResult = await Machine.updateOne(
135	        {
136	          $or: [{ relayId }, { smibBoard: relayId }],
137	        },
138	        {
139	          $set: {
140	            'smibConfig.ota.firmwareUpdatedAt': new Date(),
141	          },
142	        }
143	      );
144	      if (updateResult.modifiedCount === 0) {
145	        console.warn(
146	          `[SMIB OTA Update] No machine found with relayId: ${relayId}`
147	        );
148	      }
149	    } catch {
150	      return NextResponse.json(
151	        {
152	          success: false,
153	          error: 'Failed to send OTA update commands to SMIB',
154	        },
155	        { status: 500 }
156	      );
157	    }
158	
159	    // ============================================================================
160	    // STEP 9: Log activity
161	    // ============================================================================
162	    const currentUser = await getUserFromServer();
163	    const clientIP = getClientIP(request);
164	
165	    if (currentUser && currentUser.emailAddress) {
166	      try {
167	        await logActivity({
168	          action: 'UPDATE',
169	          details: `OTA firmware update initiated for SMIB ${relayId} - File: ${fileName}`,
170	          ipAddress: clientIP || undefined,
171	          userAgent: request.headers.get('user-agent') || undefined,
172	          userId: currentUser._id as string,
173	          username: currentUser.emailAddress as string,
174	          metadata: {
175	            resource: 'smib',
176	            resourceId: relayId,
177	            resourceName: relayId,
178	            relayId,
179	            firmwareId,
180	            fileName,
181	            firmwareBinUrl,
182	            initiatedAt: new Date().toISOString(),
183	            changes: [
184	              {
185	                field: 'firmware',
186	                oldValue: 'Previous firmware',
187	                newValue: fileName,
188	              },
189	              {
190	                field: 'otaURL',
191	                oldValue: 'Previous OTA URL',
192	                newValue: firmwareBinUrl,
193	              },
194	            ],
195	          },
196	        });
197	      } catch (logError) {
198	        console.error('Failed to log activity:', logError);
199	      }
200	    }
201	
202	    // ============================================================================
203	    // STEP10: Return success response
204	    // ============================================================================
205	    const duration = Date.now() - startTime;
206	    logRouteCreate(
207	      functionName,
208	      'POST',
209	      '/api/smib/ota-update',
210	      1,
211	      user,
212	      duration
213	    );
214	
215	    if (duration > 1000) {
216	      console.warn(`[SMIB OTA Update API] Completed in ${duration}ms`);
217	    }
218	    return NextResponse.json({
219	      success: true,
220	      message:
221	        'OTA update initiated successfully. This process may take several minutes.',
222	      relayId,
223	      firmwareId,
224	      fileName,
225	      firmwareBinUrl,
226	    });
227	  } catch (error) {
228	    const duration = Date.now() - startTime;
229	    const errorMessage =
230	      error instanceof Error ? error.message : 'Internal server error';
231	    logRouteError(
232	      functionName,
233	      'POST',
234	      '/api/smib/ota-update',
235	      errorMessage,
236	      user
237	    );
238	    console.error(
239	      `[SMIB OTA Update API] Error after ${duration}ms:`,
240	      errorMessage
241	    );
242	    return NextResponse.json(
243	      { success: false, error: errorMessage },
244	      { status: 500 }
245	    );
246	  }
247	}
