13	
14	import { logActivity } from '@/app/api/lib/helpers/activityLogger';
15	import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
16	import { connectDB } from '@/app/api/lib/middleware/db';
17	import { Machine } from '@/app/api/lib/models/machines';
18	import { mqttService } from '@/app/api/lib/services/mqttService';
