43	  const functionName = 'POST /api/smib/restart';
44	  const user = extractUserFromRequest(request);
45	
46	  try {
47	    // ============================================================================
48	    // STEP 1: Parse request body
49	    // ============================================================================
50	    const { relayId } = await request.json();
51	
52	    // ============================================================================
53	    // STEP 2: Validate relayId
54	    // ============================================================================
55	    if (!relayId) {
56	      logRouteError(
