76	    // ============================================================================
77	
78	    if (!relayId) {
79	      logRouteError(
80	        functionName,
81	        'POST',
82	        '/api/smib/restart',
83	        'RelayId is required',
84	        user
85	      );
86	      return NextResponse.json(
87	        { success: false, error: 'RelayId is required' },
