1	/**
2	 * Schedulers API Route
3	 *
4	 * This route handles fetching collection schedulers with filtering.
5	 * It supports:
6	 * - Licencee filtering
7	 * - Location filtering
8	 * - Collector filtering
9	 * - Status filtering
10	 * - Date range filtering
11	 *
12	 * @module app/api/schedulers/route
13	 */
14	
15	import { connectDB } from '@/app/api/lib/middleware/db';
16	import Scheduler from '@/app/api/lib/models/scheduler';
17	import type { MongoDBQueryValue } from '@/lib/types/common';
18	import {
19	  logRouteFetch,
20	  logRouteError,
21	  extractUserFromRequest,
22	} from '@/app/api/lib/utils/routeLogger';
23	import { NextRequest, NextResponse } from 'next/server';
24	
25	/**
26	 * Main GET handler for fetching schedulers
27	 *
28	 * @param {string} licencee - Filter by licencee ID or "all"
29	 * @param {string} location - Filter by location ID or "all"
30	 * @param {string} collector - Filter by collector user ID or "all"
31	 * @param {string} status - Filter by scheduler status
32	 * @param {string} startDate - Range start for scheduler startTime
33	 * @param {string} endDate - Range end for scheduler startTime
34	 *
35	 * Flow:
36	 * 1. Connect to database
37	 * 2. Parse query parameters (licencee, location, collector, status, dates)
38	 * 3. Build query filters
39	 * 4. Fetch schedulers from database
40	 * 5. Return schedulers list
41	 */
42	export async function GET(request: NextRequest) {
43	  const startTime = Date.now();
44	  const functionName = 'GET /api/schedulers';
45	  const user = extractUserFromRequest(request);
46	
47	  try {
48	    // ============================================================================
49	    // STEP 1: Connect to database
50	    // ============================================================================
51	    await connectDB();
52	
53	    // ============================================================================
54	    // STEP 2: Parse query parameters
55	    // ============================================================================
56	    const searchParams = request.nextUrl.searchParams;
57	    const licencee = searchParams.get('licencee');
58	    const location = searchParams.get('location');
59	    const collector = searchParams.get('collector');
60	    const status = searchParams.get('status');
61	    const startDate = searchParams.get('startDate');
62	    const endDate = searchParams.get('endDate');
63	
64	    // ============================================================================
65	    // STEP 3: Build query filters
66	    // ============================================================================
67	    // Always exclude soft-deleted records
68	    const query: Record<string, MongoDBQueryValue> = {
69	      deletedAt: { $exists: false },
70	    };
71	
72	    if (licencee && licencee.toLowerCase() !== 'all') {
73	      query.licencee = licencee;
74	    }
75	
76	    if (location && location.toLowerCase() !== 'all') {
77	      query.location = location;
78	    }
79	
80	    if (collector && collector.toLowerCase() !== 'all') {
81	      query.collector = collector;
82	    }
83	
84	    if (status && status.toLowerCase() !== 'all') {
85	      query.status = status;
86	    }
87	
88	    // Date range filter
89	    if (startDate || endDate) {
90	      query.startTime = {} as Record<string, Date>;
91	      if (startDate) {
92	        (query.startTime as Record<string, Date>).$gte = new Date(startDate);
93	      }
94	      if (endDate) {
95	        (query.startTime as Record<string, Date>).$lte = new Date(endDate);
96	      }
97	    }
98	
99	    // ============================================================================
100	    // STEP 4: Fetch schedulers from database with aggregated names
101	    // ============================================================================
102	    const schedulers = await Scheduler.aggregate([
103	      { $match: query },
104	      { $sort: { startTime: -1 } },
105	      // Join with GamingLocations for location name
106	      {
107	        $lookup: {
108	          from: 'gaminglocations',
109	          localField: 'location',
110	          foreignField: '_id',
111	          as: 'locationInfo',
112	        },
113	      },
114	      // Join with Users for collector name
115	      {
116	        $lookup: {
117	          from: 'users',
118	          localField: 'collector',
119	          foreignField: '_id',
120	          as: 'collectorInfo',
121	        },
122	      },
123	      // Join with Users for creator (manager) name
124	      {
125	        $lookup: {
126	          from: 'users',
127	          localField: 'creator',
128	          foreignField: '_id',
129	          as: 'creatorInfo',
130	        },
131	      },
132	      // Project fields to include names
133	      {
134	        $addFields: {
135	          locationName: {
136	            $ifNull: [{ $arrayElemAt: ['$locationInfo.name', 0] }, '$location'],
137	          },
138	          collectorName: {
139	            $let: {
140	              vars: { user: { $arrayElemAt: ['$collectorInfo', 0] } },
141	              in: {
142	                $cond: {
143	                  if: {
144	                    $and: [
145	                      '$$user.profile.firstName',
146	                      '$$user.profile.lastName',
147	                    ],
148	                  },
149	                  then: {
150	                    $concat: [
151	                      '$$user.profile.firstName',
152	                      ' ',
153	                      '$$user.profile.lastName',
154	                    ],
155	                  },
156	                  else: { $ifNull: ['$$user.username', '$collector'] },
157	                },
158	              },
159	            },
160	          },
161	          creatorName: {
162	            $let: {
163	              vars: { user: { $arrayElemAt: ['$creatorInfo', 0] } },
164	              in: {
165	                $cond: {
166	                  if: {
167	                    $and: [
168	                      '$$user.profile.firstName',
169	                      '$$user.profile.lastName',
170	                    ],
171	                  },
172	                  then: {
173	                    $concat: [
174	                      '$$user.profile.firstName',
175	                      ' ',
176	                      '$$user.profile.lastName',
177	                    ],
178	                  },
179	                  else: { $ifNull: ['$$user.username', '$creator'] },
180	                },
181	              },
182	            },
183	          },
184	        },
185	      },
186	      // Remove the join detail fields
187	      {
188	        $project: {
189	          locationInfo: 0,
190	          collectorInfo: 0,
191	          creatorInfo: 0,
192	        },
193	      },
194	    ]);
195	
196	    // ============================================================================
197	    // STEP 5: Return schedulers list
198	    // ============================================================================
199	    const duration = Date.now() - startTime;
200	    logRouteFetch(
201	      functionName,
202	      'GET',
203	      '/api/schedulers',
204	      schedulers.length,
205	      user,
206	      duration
207	    );
208	
209	    if (duration > 1000) {
210	      console.warn(`[Schedulers API] Completed in ${duration}ms`);
211	    }
212	
213	    return NextResponse.json(schedulers);
214	  } catch (error: unknown) {
215	    const duration = Date.now() - startTime;
216	    const errorMessage =
217	      error instanceof Error ? error.message : 'Unknown error occurred';
218	    logRouteError(functionName, 'GET', '/api/schedulers', errorMessage, user);
219	    console.error(`[Schedulers API] Error after ${duration}ms:`, errorMessage);
220	    return NextResponse.json(
221	      { error: 'Failed to fetch schedulers', details: errorMessage },
222	      { status: 500 }
223	    );
224	  }
225	}
