1	/**
2	 * Scheduler [schedulerId] API Route
3	 *
4	 * PATCH  — Edit a schedule's startTime, endTime, or status.
5	 * DELETE — Soft-delete a schedule (sets deletedAt timestamp).
6	 *
7	 * Access: manager, admin, location admin, owner, developer
8	 *
9	 * @module app/api/schedulers/[schedulerId]/route
10	 */
11	
12	import {
13	  calculateChanges,
14	  logActivity,
15	} from '@/app/api/lib/helpers/activityLogger';
16	import { connectDB } from '@/app/api/lib/middleware/db';
17	import { getUserFromServer } from '@/app/api/lib/helpers/users';
18	import Scheduler from '@/app/api/lib/models/scheduler';
19	import type { SchedulerDocument } from '@shared/types';
20	import {
21	  logRouteUpdate,
22	  logRouteDelete,
23	  logRouteError,
24	  extractUserFromRequest,
25	} from '@/app/api/lib/utils/routeLogger';
26	import { NextRequest, NextResponse } from 'next/server';
27	
28	const MANAGE_ROLES = [
29	  'manager',
30	  'admin',
31	  'location admin',
32	  'owner',
33	  'developer',
34	];
35	
36	type RouteContext = { params: Promise<{ schedulerId: string }> };
37	
38	// ============================================================================
39	// PATCH — Edit schedule fields
40	// ============================================================================
41	/**
42	 * PATCH /api/schedulers/[schedulerId]
43	 *
44	 * Updates one or more fields on an existing schedule. Only provided fields are
45	 * applied; at least one field must be included. Requires manager, admin,
46	 * location admin, owner, or developer role.
47	 *
48	 * Path params:
49	 * @param {string} schedulerId - Required. The ID of the schedule to update.
50	 *
51	 * Body fields:
52	 * @param {string} [startTime] - Optional. ISO 8601 date-time string for the new start time.
53	 * @param {string} [endTime] - Optional. ISO 8601 date-time string for the new end time.
54	 * @param {string} [status] - Optional. New status value for the schedule.
55	 */
56	export async function PATCH(request: NextRequest, context: RouteContext) {
57	  const timerStart = Date.now();
58	  const functionName = 'PATCH /api/schedulers/[schedulerId]';
59	  const logUser = extractUserFromRequest(request);
60	
61	  try {
62	    // ============================================================================
63	    // STEP 1: Connect to database
64	    // ============================================================================
65	    await connectDB();
66	
67	    // ============================================================================
68	    // STEP 2: Authenticate user & role check
69	    // ============================================================================
70	    const user = await getUserFromServer();
71	    const userRoles = (user?.roles as string[]) || [];
72	    if (!user || !userRoles.some((r: string) => MANAGE_ROLES.includes(r))) {
73	      return NextResponse.json(
74	        {
75	          success: false,
76	          error: 'Unauthorized',
77	          message: 'Insufficient permissions',
78	          timestamp: new Date().toISOString(),
79	        },
80	        { status: 403 }
81	      );
82	    }
83	
84	    // ============================================================================
85	    // STEP 3: Parse request body
86	    // ============================================================================
87	    const { schedulerId } = await context.params;
88	    const body = await request.json();
89	    const { startTime, endTime, status } = body as {
90	      startTime?: string;
91	      endTime?: string;
92	      status?: string;
93	    };
94	
95	    // ============================================================================
96	    // STEP 4: Build update data
97	    // ============================================================================
98	    const updateData: Record<string, unknown> = {};
99	    if (startTime) updateData.startTime = new Date(startTime);
100	    if (endTime) updateData.endTime = new Date(endTime);
101	    if (status) updateData.status = status;
102	
103	    if (Object.keys(updateData).length === 0) {
104	      return NextResponse.json(
105	        {
106	          success: false,
107	          error: 'No fields to update',
108	          message: 'Provide at least one field to update',
109	          timestamp: new Date().toISOString(),
110	        },
111	        { status: 400 }
112	      );
113	    }
114	
115	    console.log(
116	      `[Scheduler PATCH] Request — schedulerId: ${schedulerId}, fields: ${Object.keys(updateData).join(', ')}`
117	    );
118	
119	    // ============================================================================
120	    // STEP 5: Fetch existing scheduler
121	    // ============================================================================
122	    const existingScheduler = await Scheduler.findOne({
123	      _id: schedulerId,
124	      deletedAt: { $exists: false },
125	    }).lean<SchedulerDocument>();
126	    if (!existingScheduler) {
127	      return NextResponse.json(
128	        {
129	          success: false,
130	          error: 'Not found',
131	          message: 'Schedule not found',
132	          timestamp: new Date().toISOString(),
133	        },
134	        { status: 404 }
135	      );
136	    }
137	
138	    // ============================================================================
139	    // STEP 6: Update scheduler
140	    // ============================================================================
141	    const updated = await Scheduler.findOneAndUpdate(
142	      { _id: schedulerId, deletedAt: { $exists: false } },
143	      { $set: updateData },
144	      { new: true }
145	    );
146	
147	    if (!updated) {
148	      return NextResponse.json(
149	        {
150	          success: false,
151	          error: 'Not found',
152	          message: 'Schedule not found',
153	          timestamp: new Date().toISOString(),
154	        },
155	        { status: 404 }
156	      );
157	    }
158	
159	    // ============================================================================
160	    // STEP 7: Log activity
161	    // ============================================================================
162	    console.log(`[Scheduler PATCH] Updated scheduler ${schedulerId}`);
163	    logActivity({
164	      action: 'update',
165	      details: `Schedule ${schedulerId} updated`,
166	      userId: String(user._id),
167	      username: String(
168	        (user as Record<string, unknown>).emailAddress ||
169	          (user as Record<string, unknown>).username ||
170	          user._id
171	      ),
172	      metadata: {
173	        resource: 'scheduler',
174	        resourceId: schedulerId,
175	        resourceName: `Schedule ${schedulerId}`,
176	        changes: calculateChanges(
177	          existingScheduler as Record<string, unknown>,
178	          updateData
179	        ),
180	        previousData: existingScheduler,
181	        newData: updated.toObject(),
182	      },
183	    }).catch(err =>
184	      console.error('[Scheduler PATCH] Activity log failed:', err)
185	    );
186	
187	    // ============================================================================
188	    // STEP 8: Return success response
189	    // ============================================================================
190	    const duration = Date.now() - timerStart;
191	    logRouteUpdate(
192	      functionName,
193	      'PATCH',
194	      '/api/schedulers/[schedulerId]',
195	      1,
196	      logUser,
197	      duration
198	    );
199	
200	    return NextResponse.json({
201	      success: true,
202	      data: updated,
203	      message: 'Schedule updated successfully',
204	      timestamp: new Date().toISOString(),
205	    });
206	  } catch (error: unknown) {
207	    const msg = error instanceof Error ? error.message : 'Unknown error';
208	    logRouteError(
209	      functionName,
210	      'PATCH',
211	      '/api/schedulers/[schedulerId]',
212	      msg,
213	      logUser
214	    );
215	    console.error('[Scheduler PATCH] Error:', msg);
216	    return NextResponse.json(
217	      {
218	        success: false,
219	        error: 'Failed to update schedule',
220	        message: msg,
221	        timestamp: new Date().toISOString(),
222	      },
223	      { status: 500 }
224	    );
225	  }
226	}
