235	 * retained in the database but excluded from all active queries. Requires
236	 * manager, admin, location admin, owner, or developer role.
237	 *
238	 * Path params:
239	 * @param {string} schedulerId - Required. The ID of the schedule to delete.
240	 */
241	export async function DELETE(_request: NextRequest, context: RouteContext) {
242	  const startTime = Date.now();
243	  const functionName = 'DELETE /api/schedulers/[schedulerId]';
244	  const logUser = extractUserFromRequest(_request);
245	
246	  try {
247	    // ============================================================================
248	    // STEP 1: Connect to database
249	    // ============================================================================
250	    await connectDB();
251	
