1	/**
2	 * GET /api/manufacturers
3	 *
4	 * Returns a sorted, deduplicated list of all machine manufacturer names sourced
5	 * from the machines collection. Called by filter dropdowns and machine management
6	 * forms. Merges the 'manufacturer' and 'manuf' fields to handle legacy data.
7	 * Requires authentication via withApiAuth.
8	 *
9	 * No query parameters.
10	 *
11	 * @module app/api/manufacturers/route
12	 */
13	
14	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
15	import { Machine } from '@/app/api/lib/models/machines';
16	import {
17	  logRouteFetch,
18	  logRouteError,
19	  extractUserFromRequest,
20	} from '@/app/api/lib/utils/routeLogger';
21	import { NextRequest, NextResponse } from 'next/server';
22	
23	export async function GET(req: NextRequest) {
24	  const startTime = Date.now();
25	  const functionName = 'GET /api/manufacturers';
26	  const user = extractUserFromRequest(req);
27	
28	  return withApiAuth(req, async () => {
29	    try {
30	      // ============================================================================
31	      // STEP 1: Fetch and aggregate manufacturers
32	      // ============================================================================
33	      const manufacturers = await Machine.aggregate([
34	        { $project: { manufacturer: 1, manuf: 1 } },
35	        {
36	          $group: {
37	            _id: null,
38	            manufacturers: { $addToSet: '$manufacturer' },
39	            manufs: { $addToSet: '$manuf' },
40	          },
41	        },
42	        {
43	          $project: {
44	            _id: 0,
45	            allManufacturers: { $setUnion: ['$manufacturers', '$manufs'] },
46	          },
47	        },
48	      ]);
49	
50	      // ============================================================================
51	      // STEP 2: Filter and sort manufacturers
52	      // ============================================================================
53	      const uniqueManufacturers = manufacturers[0]?.allManufacturers || [];
54	      const filteredManufacturers = uniqueManufacturers.filter(
55	        (m: unknown) =>
56	          m && typeof m === 'string' && (m as string).trim() !== ''
57	      );
58	      const sortedManufacturers = filteredManufacturers.sort();
59	
60	      // ============================================================================
61	      // STEP 3: Return success response
62	      // ============================================================================
63	      const duration = Date.now() - startTime;
64	      logRouteFetch(
65	        functionName,
66	        'GET',
67	        '/api/manufacturers',
68	        sortedManufacturers.length,
69	        user,
70	        duration
71	      );
72	      return NextResponse.json(sortedManufacturers);
73	    } catch (error) {
74	      const errorMessage = error instanceof Error ? error.message : 'Failed';
75	      logRouteError(
76	        functionName,
77	        'GET',
78	        '/api/manufacturers',
79	        errorMessage,
80	        user
81	      );
82	      return NextResponse.json({ error: 'Failed' }, { status: 500 });
83	    }
84	  });
85	}
