251	export async function GET(request: NextRequest) {
252	  const startTime = Date.now();
253	  const functionName = 'GET /api/feedback';
254	  const logUser = extractUserFromRequest(request);
255	
256	  try {
257	    // ============================================================================
258	    // STEP 1: Connect to database
259	    // ============================================================================
260	    await connectDB();
261	
262	    // ============================================================================
263	    // STEP 2: Authenticate user and check admin role
264	    // ============================================================================
265	    const authResult = await authenticateAdminUser('GET', functionName, logUser);
266	    if (authResult instanceof NextResponse) return authResult;
267	
268	    // ============================================================================
269	    // STEP 3: Parse query parameters and build query
270	    // ============================================================================
271	    const { searchParams } = new URL(request.url);
272	    const emailFilter = searchParams.get('email') || '';
273	    const categoryFilter = searchParams.get('category') || '';
274	    const statusFilter = searchParams.get('status') || '';
275	    const page = parseInt(searchParams.get('page') || '1', 10);
276	    const limit = parseInt(searchParams.get('limit') || '50', 10);
277	    const skip = (page - 1) * limit;
278	
279	    const query = buildFeedbackQuery({ emailFilter, categoryFilter, statusFilter });
280	
281	    // ============================================================================
282	    // STEP 4: Fetch feedback with pagination
283	    // ============================================================================
284	    const totalCount = await FeedbackModel.countDocuments(query);
285	    const feedback = await FeedbackModel.find(query)
286	      .sort({ submittedAt: -1 })
287	      .skip(skip)
288	      .limit(limit)
289	      .lean<FeedbackDocument[]>()
290	      .exec();
291	
292	    // ============================================================================
293	    // STEP 5: Return paginated feedback list
294	    // ============================================================================
295	    const duration = Date.now() - startTime;
296	    if (duration > 1000) {
297	      console.warn(`[Feedback API] GET completed in ${duration}ms`);
298	    }
299	
300	    logRouteFetch(functionName, 'GET', '/api/feedback', feedback.length, logUser, duration);
301	    return NextResponse.json(
302	      {
303	        success: true,
304	        data: feedback,
305	        pagination: {
306	          page,
307	          limit,
308	          totalCount,
309	          totalPages: Math.ceil(totalCount / limit),
310	        },
311	      },
312	      { status: 200 }
313	    );
314	  } catch (error) {
315	    const errorMessage =
316	      error instanceof Error ? error.message : 'Failed to fetch feedback';
317	    console.error('Error fetching feedback:', error);
318	    logRouteError(functionName, 'GET', '/api/feedback', errorMessage, logUser);
319	    return NextResponse.json(
320	      { success: false, error: 'Failed to fetch feedback. Please try again later.' },
321	      { status: 500 }
322	    );
323	  }
324	}
