34	    const endDateParam = searchParams.get('endDate');
35	
36	    if (!locationId && !locationIds) {
37	      logRouteError(
38	        functionName,
39	        'GET',
40	        '/api/metrics/hourly-trends',
41	        'Location ID or Location IDs are required',
42	        user
43	      );
44	      return NextResponse.json(
45	        { error: 'Location ID or Location IDs are required' },
46	        { status: 400 }
47	      );
