1	/**
2	 * Top Performing Metrics API Route
3	 *
4	 * This route handles fetching top performing locations or cabinets based on moneyIn (drop).
5	 * It supports:
6	 * - Filtering by activeTab (locations or cabinets)
7	 * - Filtering by timePeriod (Today, Yesterday, 7d, 30d)
8	 * - Optional filtering by licencee
9	 *
10	 * @module app/api/metrics/top-performing/route
11	 */
12	
13	import { shouldApplyCurrencyConversion } from '@/app/api/lib/helpers/currency/helper';
14	import { getTopPerformingMetrics } from '@/app/api/lib/helpers/reports/topPerforming';
15	import type { TopPerformingItem } from '@/app/api/lib/helpers/currency/topPerforming';
16	import { convertTopPerformingCurrency } from '@/app/api/lib/helpers/currency/topPerforming';
17	import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
18	import { connectDB } from '@/app/api/lib/middleware/db';
19	import type { TimePeriod } from '@/app/api/lib/types';
20	import { resolveLicenceeId } from '@/lib/utils/licencee';
21	import type { CurrencyCode } from '@/shared/types/currency';
22	import { NextRequest, NextResponse } from 'next/server';
23	import type { TopPerformingTab } from '@/shared/types/reports';
24	import {
25	  logRouteFetch,
26	  logRouteError,
27	  extractUserFromRequest,
28	} from '@/app/api/lib/utils/routeLogger';
29	
30	/**
31	 * Main GET handler for fetching top performing metrics
32	 *
33	 * @param {string} activeTab - Tab to analyze ('locations' or 'Cabinets')
34	 * @param {string} timePeriod - Time range preset ('7d' default)
35	 * @param {string} licencee - Filter by licencee name or ID
36	 * @param {string} currency - Target display currency
37	 * @param {string} startDate - ISO date for custom range start
38	 * @param {string} endDate - ISO date for custom range end
39	 *
40	 * Flow:
41	 * 1. Parse and validate request parameters
42	 * 2. Connect to database
43	 * 3. Fetch top performing metrics
44	 * 4. Apply currency conversion if needed
45	 * 5. Return top performing data
46	 */
47	export async function GET(req: NextRequest) {
48	  const startTime = Date.now();
49	  const functionName = 'GET /api/metrics/top-performing';
50	  const user = extractUserFromRequest(req);
51	
52	  try {
53	    // ============================================================================
54	    // STEP 1: Parse and validate request parameters
55	    // ============================================================================
56	    const searchParams = req.nextUrl.searchParams;
57	    const activeTab =
58	      (searchParams.get('activeTab') as TopPerformingTab) || 'locations';
59	    const timePeriod: TimePeriod =
60	      (searchParams.get('timePeriod') as TimePeriod) || '7d';
61	
62	    // Raw licencee from query (name, id, or "all")
63	    const rawLicencee = searchParams.get('licencee') || null;
64	
65	    // Normalize licencee for DB filtering:
66	    // - Resolve known names (TTG, Cabana, etc.) → ID
67	    // - Treat "all" / empty as undefined (no filter)
68	    let licenceeForFilter: string | undefined;
69	    if (rawLicencee && rawLicencee !== 'all') {
70	      licenceeForFilter = resolveLicenceeId(rawLicencee) || rawLicencee;
71	    }
72	
73	    const currencyParam = searchParams.get('currency') as CurrencyCode | null;
74	    const displayCurrency: CurrencyCode = currencyParam || 'USD';
75	
76	    // Parse custom date range for Custom time period
77	    const startDateParam = searchParams.get('startDate');
78	    const endDateParam = searchParams.get('endDate');
79	    let customStartDate: Date | undefined;
80	    let customEndDate: Date | undefined;
81	
82	    if (timePeriod === 'Custom' && startDateParam && endDateParam) {
83	      customStartDate = new Date(startDateParam);
84	      customEndDate = new Date(endDateParam);
85	
86	      // Validate dates
87	      if (isNaN(customStartDate.getTime()) || isNaN(customEndDate.getTime())) {
88	        logRouteError(
89	          functionName,
90	          'GET',
91	          '/api/metrics/top-performing',
92	          'Invalid date parameters',
93	          user
94	        );
95	        return NextResponse.json(
96	          { error: 'Invalid date parameters' },
97	          { status: 400 }
98	        );
99	      }
100	    }
101	
102	    // ============================================================================
103	    // STEP 2: Connect to database
104	    // ============================================================================
105	    const db = await connectDB();
106	    if (!db) {
107	      logRouteError(
108	        functionName,
109	        'GET',
110	        '/api/metrics/top-performing',
111	        'Database connection failed',
112	        user
113	      );
114	      return NextResponse.json(
115	        { error: 'Database connection failed' },
116	        { status: 500 }
117	      );
118	    }
119	
120	    // ============================================================================
121	    // STEP 3: Fetch top performing metrics
122	    // ============================================================================
123	    const data = await getTopPerformingMetrics(
124	      activeTab,
125	      timePeriod,
126	      licenceeForFilter,
127	      customStartDate,
128	      customEndDate
129	    );
130	
131	    // ============================================================================
132	    // STEP 4: Apply currency conversion if needed
133	    // ============================================================================
134	    const currentUser = await getUserFromServer();
135	    const currentUserRoles = (currentUser?.roles as string[]) || [];
136	    const isAdminOrDev =
137	      currentUserRoles.includes('admin') ||
138	      currentUserRoles.includes('developer') ||
139	      currentUserRoles.includes('owner');
140	
141	    let convertedData = data as unknown as TopPerformingItem[];
142	
143	    // Currency conversion ONLY for Admin/Developer when viewing "All Licencees" (no specific licencee selected)
144	    // Only apply conversion if "all licencees" is selected AND display currency is not USD
145	    const shouldConvert =
146	      isAdminOrDev &&
147	      shouldApplyCurrencyConversion(rawLicencee) &&
148	      displayCurrency &&
149	      displayCurrency !== 'USD';
150	
151	    if (shouldConvert) {
152	      convertedData = await convertTopPerformingCurrency(
153	        convertedData,
154	        displayCurrency
155	      );
156	    }
157	
158	    // ============================================================================
159	    // STEP 5: Return top performing data
160	    // ============================================================================
161	    const duration = Date.now() - startTime;
162	    logRouteFetch(
163	      functionName,
164	      'GET',
165	      '/api/metrics/top-performing',
166	      (convertedData as unknown[]).length,
167	      user,
168	      duration
169	    );
170	    if (duration > 1000) {
171	      console.warn(`[Top Performing API] Completed in ${duration}ms`);
172	    }
173	    return NextResponse.json({
174	      activeTab,
175	      timePeriod,
176	      data: convertedData,
177	      currency: displayCurrency,
178	    });
179	  } catch (error) {
180	    const duration = Date.now() - startTime;
181	    const errorMessage =
182	      error instanceof Error ? error.message : 'Internal Server Error';
183	    logRouteError(
184	      functionName,
185	      'GET',
186	      '/api/metrics/top-performing',
187	      errorMessage,
188	      user
189	    );
190	    console.error(
191	      `[Top Performing Metrics GET API] Error after ${duration}ms:`,
192	      errorMessage
193	    );
194	    return NextResponse.json({ error: errorMessage }, { status: 500 });
195	  }
196	}
