64	  const user = extractUserFromRequest(
65	    request as unknown as import('next/server').NextRequest
66	  );
67	  const logs: string[] = [];
68	  const log = (msg: string) => {
69	    const timestamped = `[${new Date().toISOString()}] ${msg}`;
70	    console.log(timestamped);
71	    logs.push(timestamped);
72	  };
73	
74	  // Backup current URI to restore later if needed
75	  const originalUri = process.env.MONGODB_URI || '';
76	
77	  try {
78	    // ============================================================================
79	    // STEP 0: Clean up any existing connection to avoid Mongoose conflict
