1	/**
2	 * E2E Test Auth Endpoint
3	 *
4	 * Generates a real JWT for a mock user and sets it as an auth cookie.
5	 * Only available in development/test environments — returns 404 in production.
6	 *
7	 * Used by Playwright's auth fixture so tests receive a properly signed
8	 * token that the Next.js middleware (proxy.ts) will accept.
9	 */
10	
11	import { NextRequest, NextResponse } from 'next/server';
12	import { generateAccessToken } from '@/lib/utils/auth';
13	import { getAuthCookieOptions } from '@/lib/utils/cookieSecurity';
14	import {
15	  logRouteCreate,
16	  logRouteError,
17	  extractUserFromRequest,
18	} from '@/app/api/lib/utils/routeLogger';
19	
20	/**
21	 * POST /api/e2e/auth
22	 *
23	 * @body {Object} user - REQUIRED. MockUserPayload containing _id, username, roles, etc.
24	 */
25	export async function POST(request: NextRequest) {
26	  const startTime = Date.now();
27	  const functionName = 'POST /api/e2e/auth';
28	  const logUser = extractUserFromRequest(request);
29	
30	  // ============================================================================
31	  // STEP 1: Verify environment
32	  // ============================================================================
33	  // Only available outside production unless specifically enabled
34	  if (
35	    process.env.NODE_ENV === 'production' &&
36	    process.env.ENABLE_E2E_AUTH !== 'true'
37	  ) {
38	    logRouteError(functionName, 'POST', '/api/e2e/auth', 'Not found', logUser);
39	    return NextResponse.json({ error: 'Not found' }, { status: 404 });
40	  }
41	
42	  // ============================================================================
43	  // STEP 2: Parse request body
44	  // ============================================================================
45	  const body = await request.json();
46	  const user = body.user as {
47	    _id: string;
48	    username: string;
49	    emailAddress: string;
50	    isEnabled: boolean;
51	    roles?: string[];
52	    assignedLocations?: string[];
53	    assignedLicencees?: string[];
54	  };
55	
56	  if (!user?._id) {
57	    logRouteError(
58	      functionName,
59	      'POST',
60	      '/api/e2e/auth',
61	      'user._id is required',
62	      logUser
63	    );
64	    return NextResponse.json(
65	      { error: 'user._id is required' },
66	      { status: 400 }
67	    );
68	  }
69	
70	  // ============================================================================
71	  // STEP 3: Generate access token
72	  // ============================================================================
73	  // generateAccessToken automatically fills sessionId and dbContext from env
74	  const token = await generateAccessToken({
75	    _id: user._id,
76	    username: user.username,
77	    emailAddress: user.emailAddress,
78	    isEnabled: user.isEnabled,
79	    roles: user.roles,
80	    assignedLocations: user.assignedLocations,
81	    assignedLicencees: user.assignedLicencees,
82	    sessionId: `e2e-session-${user._id}`,
83	    dbContext: { connectionString: '', timestamp: 0 }, // overwritten by generateAccessToken
84	  });
85	
86	  // ============================================================================
87	  // STEP 4: Set auth cookie and return response
88	  // ============================================================================
89	  const response = NextResponse.json({
90	    success: true,
91	    data: { user },
92	    timestamp: new Date().toISOString(),
93	  });
94	
95	  const cookieOptions = getAuthCookieOptions(request, {
96	    maxAge: 60 * 60 * 24 * 7, // 7 days
97	  });
98	  response.cookies.set('token', token, cookieOptions);
99	
100	  const duration = Date.now() - startTime;
101	  logRouteCreate(functionName, 'POST', '/api/e2e/auth', 1, logUser, duration);
102	
103	  return response;
104	}
