1	/**
2	 * Collection Report V2 — Custom System Meters Calculation API
3	 *
4	 * GET /api/collection-reports-v2/custom-meters
5	 * Calculates system meters for a custom collection period by summing drop
6	 * and totalCancelledCredits outside the movement object in the Meters collection.
7	 */
8	
9	import { connectDB } from '@/app/api/lib/middleware/db';
10	import { Meters } from '@/app/api/lib/models/meters';
11	import { getUserFromServer } from '@/app/api/lib/helpers/users';
12	import { NextRequest, NextResponse } from 'next/server';
13	
14	export async function GET(req: NextRequest) {
15	  try {
16	    // ============================================================================
17	    // STEP 1: Connect to database
18	    // ============================================================================
19	    await connectDB();
20	
21	    // ============================================================================
22	    // STEP 2: Authenticate user
23	    // ============================================================================
24	    const userPayload = await getUserFromServer();
25	    if (!userPayload) {
26	      return NextResponse.json(
27	        { success: false, error: 'Unauthorized' },
28	        { status: 401 }
29	      );
30	    }
31	
32	    // ============================================================================
33	    // STEP 3: Parse and validate parameters
34	    // ============================================================================
35	    const { searchParams } = new URL(req.url);
36	    const machineId = searchParams.get('machineId');
37	    const startDate = searchParams.get('startDate');
38	    const endDate = searchParams.get('endDate');
39	
40	    if (!machineId || !startDate || !endDate) {
41	      return NextResponse.json(
42	        {
43	          success: false,
44	          error: 'machineId, startDate, and endDate are required',
45	        },
46	        { status: 400 }
47	      );
48	    }
49	
50	    // ============================================================================
51	    // STEP 4: Find the single most recent meter document in the specified range
52	    // ============================================================================
53	    const start = new Date(startDate);
54	    const end = new Date(endDate);
55	
56	    const latestMeter = await Meters.findOne({
57	      machine: machineId,
58	      readAt: { $gte: start, $lte: end },
59	    })
60	      .sort({ readAt: -1 })
61	      .lean<{ drop?: number; totalCancelledCredits?: number }>();
62	
63	    const data = {
64	      sasMetersIn: latestMeter?.drop ?? 0,
65	      sasMetersOut: latestMeter?.totalCancelledCredits ?? 0,
66	    };
67	
68	    // ============================================================================
69	    // STEP 5: Return data
70	    // ============================================================================
71	    return NextResponse.json({ success: true, data });
72	  } catch (error) {
73	    const errorMessage =
74	      error instanceof Error ? error.message : 'Internal server error';
75	    return NextResponse.json(
76	      { success: false, error: errorMessage },
77	      { status: 500 }
78	    );
79	  }
80	}
