39	// ============================================================================
40	// GET — List sessions (one row per sessionId, aggregated)
41	// ============================================================================
42	
43	export async function GET(req: NextRequest) {
44	  const startTime = Date.now();
45	  const functionName = 'GET /api/collection-reports-v2/sessions';
46	  const user = extractUserFromRequest(req);
47	
48	  try {
49	    // ============================================================================
50	    // STEP 1: Connect and authenticate
51	    // ============================================================================
52	    await connectDB();
53	    const userPayload = await getUserFromServer();
54	    if (!userPayload) {
55	      return NextResponse.json(
56	        { success: false, error: 'Unauthorized' },
57	        { status: 401 }
58	      );
59	    }
60	
61	    // ============================================================================
62	    // STEP 2: Parse query parameters
63	    // ============================================================================
64	    const { searchParams } = new URL(req.url);
65	    const rawLicencee = searchParams.get('licencee') || undefined;
66	    const licencee = resolveLicenceeParam(rawLicencee ?? null);
67	    const timePeriod = (searchParams.get('timePeriod') as TimePeriod) || undefined;
68	    const startDateStr = searchParams.get('startDate');
69	    const endDateStr = searchParams.get('endDate');
70	    const search = searchParams.get('search') || undefined;
71	    const searchType = searchParams.get('searchType') || 'collector';
72	    const page = Math.max(0, parseInt(searchParams.get('page') || '1', 10) - 1);
73	    const limit = Math.min(100, parseInt(searchParams.get('limit') || '20', 10));
74	    const sortField = searchParams.get('sortField') || 'created';
75	    const sortDir = searchParams.get('sortDirection') || 'desc';
76	
77	    const { sortKey, sortDirection } = buildSessionSortConfig(sortField, sortDir);
78	    const dateFilter = buildDateFilter(timePeriod, startDateStr, endDateStr);
79	
80	    // ============================================================================
81	    // STEP 3: Determine allowed locations and build match stage
82	    // ============================================================================
83	    const { roles, assignedLicencees, assignedLocations } = extractUserPayload(
84	      userPayload as unknown as Record<string, unknown>
85	    );
86	    const allowedLocationIds = await determineAllowedLocationIds(
87	      roles,
88	      assignedLicencees,
89	      assignedLocations
90	    );
91	    const matchStage = buildSessionListMatchStage(
92	      licencee,
93	      allowedLocationIds,
94	      dateFilter,
95	      search,
96	      searchType
97	    );
98	
99	    // ============================================================================
100	    // STEP 4: Execute aggregation and count in parallel
101	    // ============================================================================
102	    const pipeline = buildSessionListPipeline(matchStage, sortKey, sortDirection, page, limit);
103	    const countPipeline = buildSessionCountPipeline(matchStage);
104	
105	    const [sessions, totalResult] = await Promise.all([
106	      ReportedMachine.aggregate(pipeline).exec(),
107	      ReportedMachine.aggregate(countPipeline).exec(),
108	    ]);
109	
110	    const total = totalResult[0]?.total ?? 0;
111	    const duration = Date.now() - startTime;
112	    logRouteFetch(functionName, 'GET', '/api/collection-reports-v2/sessions', sessions.length, user, duration);
113	
114	    // ============================================================================
115	    // STEP 5: Return response
116	    // ============================================================================
117	    return NextResponse.json({
118	      success: true,
119	      data: sessions,
120	      pagination: {
121	        total,
122	        page: page + 1,
123	        limit,
124	        totalPages: Math.ceil(total / limit) || 1,
125	      },
126	    });
127	  } catch (error) {
128	    const errorMessage = error instanceof Error ? error.message : 'Internal server error';
129	    logRouteError(functionName, 'GET', '/api/collection-reports-v2/sessions', errorMessage, user);
130	    return NextResponse.json({ success: false, error: errorMessage }, { status: 500 });
131	  }
