134	// ============================================================================
135	// POST — Start a new capture session
136	// ============================================================================
137	
138	export async function POST(req: NextRequest) {
139	  const startTime = Date.now();
140	  const functionName = 'POST /api/collection-reports-v2/sessions';
141	  const user = extractUserFromRequest(req);
142	
143	  try {
144	    // ============================================================================
145	    // STEP 1: Connect and authenticate
146	    // ============================================================================
147	    await connectDB();
148	    const userPayload = await getUserFromServer();
149	    if (!userPayload) {
150	      return NextResponse.json(
151	        { success: false, error: 'Unauthorized' },
152	        { status: 401 }
153	      );
154	    }
155	
156	    // ============================================================================
157	    // STEP 2: Parse request body
158	    // ============================================================================
159	    const body = await req.json();
160	    const { locationId, locationName, licencee } = body as {
161	      locationId: string;
162	      locationName: string;
163	      licencee?: string;
164	    };
165	
166	    if (!locationId || !locationName) {
167	      return NextResponse.json(
168	        { success: false, error: 'locationId and locationName are required' },
169	        { status: 400 }
170	      );
171	    }
172	
173	    const collectorUserId = String((userPayload as unknown as Record<string, string>)._id);
174	    const collectorName =
175	      (userPayload as unknown as Record<string, string>).name ||
176	      (userPayload as unknown as Record<string, string>).username ||
177	      collectorUserId;
178	
179	    // ============================================================================
180	    // STEP 3: Determine session timing
181	    // ============================================================================
182	    const sessionEndTime = new Date();
183	    const previousSessionEndTime = await lookupPreviousSessionEndTime(locationId);
184	    const sessionStartTime: Date | null = previousSessionEndTime;
185	
186	    // ============================================================================
187	    // STEP 4: Verify location access
188	    // ============================================================================
189	    const payloadRecord = userPayload as unknown as Record<string, unknown>;
190	    const { roles, assignedLicencees, assignedLocations } = extractUserPayload(payloadRecord);
191	    const allowedLocationIds = await determineAllowedLocationIds(
192	      roles,
193	      assignedLicencees,
194	      assignedLocations
195	    );
196	
197	    if (allowedLocationIds !== 'all' && !allowedLocationIds.includes(locationId)) {
198	      logRouteError(functionName, 'POST', '/api/collection-reports-v2/sessions', 'Location access denied', user);
199	      return NextResponse.json(
200	        { success: false, error: 'Location access denied' },
201	        { status: 403 }
202	      );
203	    }
204	
205	    // ============================================================================
206	    // STEP 5: Fetch and map machines
207	    // ============================================================================
208	    const DELETION_FILTER = {
209	      $or: [{ deletedAt: null }, { deletedAt: { $lt: new Date('2025-01-01') } }],
210	    };
211	
212	    const machines = await Machine.find({
213	      gamingLocation: locationId,
214	      ...DELETION_FILTER,
215	    })
216	      .select('_id machineId serialNumber custom game manufacturer machineName collectionMeters sasMeters collectionTime previousCollectionTime')
217	      .sort({ 'custom.name': 1, _id: 1 })
218	      .lean<MachineDocument[]>();
219	
220	    const sessionId = await generateMongoId();
221	    const machineList = mapMachinesToV2Format(machines);
222	
223	    // ============================================================================
224	    // STEP 6: Look up last collection times per machine
225	    // ============================================================================
226	    const machineIdsList = machines.map(m => String(m._id));
227	    const lastCollectionMap = await lookupLastSessionEndTimes(machineIdsList);
228	
229	    // ============================================================================
230	    // STEP 7: Persist machines as ReportedMachine documents
231	    // ============================================================================
232	    const collectorId = String((userPayload as unknown as Record<string, string>)._id);
233	    const { reportedMachineDocs } = await buildReportedMachineDocs(
234	      machineList,
235	      sessionId,
236	      locationId,
237	      locationName,
238	      licencee || '',
239	      collectorId,
240	      collectorName,
241	      sessionStartTime ?? undefined,
242	      sessionEndTime,
243	      lastCollectionMap
244	    );
245	
246	    const inserted = await ReportedMachine.insertMany(reportedMachineDocs);
247	    const insertedIds = inserted.map(doc => doc._id);
248	
249	    const duration = Date.now() - startTime;
250	    logRouteCreate(functionName, 'POST', '/api/collection-reports-v2/sessions', inserted.length, user, duration);
251	
252	    // ============================================================================
253	    // STEP 8: Return response
254	    // ============================================================================
255	    return NextResponse.json({
256	      success: true,
257	      data: {
258	        sessionId,
259	        locationId,
260	        locationName,
261	        licencee: licencee || '',
262	        collector: collectorId,
263	        collectorName,
264	        machinesTotal: inserted.length,
265	        machines: machineList,
266	        reportedMachineIds: insertedIds,
267	      },
268	    });
269	  } catch (error) {
270	    const errorMessage = error instanceof Error ? error.message : 'Internal server error';
271	    logRouteError(functionName, 'POST', '/api/collection-reports-v2/sessions', errorMessage, user);
272	    return NextResponse.json({ success: false, error: errorMessage }, { status: 500 });
273	  }
274	}
