66	
67	function applyScaleToMachine(
68	  machine: SessionMachineResponse,
69	  moneyInScale: number,
70	  moneyOutScale: number
71	): SessionMachineResponse {
72	  if (moneyInScale === 1 && moneyOutScale === 1) return machine;
73	  const round = (val: number | null): number | null =>
74	    val === null ? null : Math.round(val * 100) / 100;
75	  return {
76	    ...machine,
77	    sasMetersIn: round(machine.sasMetersIn !== null ? machine.sasMetersIn * moneyInScale : null),
78	    sasMetersOut: round(machine.sasMetersOut !== null ? machine.sasMetersOut * moneyOutScale : null),
79	    sasGross: round(machine.sasGross !== null ? machine.sasGross * moneyInScale : null),
80	    machineGross: Math.round(machine.machineGross * moneyInScale * 100) / 100,
81	    variation: round(machine.variation !== null ? machine.variation * moneyInScale : null),
82	  };
83	}
84	
85	function applyScaleToFinancials(
86	  financials: CollectionSessionV2Document | null,
87	  moneyInScale: number,
88	  moneyOutScale: number
89	): CollectionSessionV2Document | null {
90	  if (!financials || (moneyInScale === 1 && moneyOutScale === 1)) return financials;
91	  const scaleIn = (val: number) => Math.round(val * moneyInScale * 100) / 100;
92	  const scaleOut = (val: number) => Math.round(val * moneyOutScale * 100) / 100;
93	  return {
94	    ...financials,
95	    amountToCollect: scaleIn(financials.amountToCollect ?? 0),
96	    amountCollected: scaleIn(financials.amountCollected ?? 0),
97	    amountUncollected: scaleIn(financials.amountUncollected ?? 0),
98	    partnerProfit: scaleIn(financials.partnerProfit ?? 0),
99	    variance: typeof financials.variance === 'number'
100	      ? scaleIn(financials.variance)
101	      : financials.variance,
102	    taxes: scaleOut(financials.taxes ?? 0),
103	    advance: scaleOut(financials.advance ?? 0),
104	    previousBalance: scaleOut(financials.previousBalance ?? 0),
105	    currentBalance: scaleOut(financials.currentBalance ?? 0),
106	    balanceCorrection: scaleOut(financials.balanceCorrection ?? 0),
107	  };
108	}
