352	export async function PATCH(
353	  req: NextRequest,
354	  { params }: { params: Promise<{ sessionId: string }> }
355	) {
356	  const startTime = Date.now();
357	  const functionName = 'PATCH /api/collection-reports-v2/sessions/[sessionId]';
358	  const user = extractUserFromRequest(req);
359	  let sessionId = '';
360	
361	  try {
362	    // ============================================================================
363	    // STEP 1: Connect and authenticate
364	    // ============================================================================
365	    await connectDB();
366	    const userPayload = await getUserFromServer();
367	    if (!userPayload) {
368	      return NextResponse.json(
369	        { success: false, error: 'Unauthorized' },
370	        { status: 401 }
371	      );
372	    }
373	
374	    // ============================================================================
375	    // STEP 2: Parse request params and body
376	    // ============================================================================
377	    sessionId = (await params).sessionId;
378	    if (!sessionId) {
379	      return NextResponse.json(
380	        { success: false, error: 'sessionId is required' },
381	        { status: 400 }
382	      );
383	    }
384	
385	    const body = await req.json() as Record<string, unknown>;
386	    const { sessionStartTime, sessionEndTime } = body as {
387	      sessionStartTime?: string;
388	      sessionEndTime?: string;
389	    };
390	
391	    // ============================================================================
392	    // STEP 3: Update session time fields on ReportedMachine docs
393	    // ============================================================================
394	    const timeUpdateFields: Record<string, unknown> = {};
395	    if (sessionStartTime) timeUpdateFields.sessionStartTime = new Date(sessionStartTime);
396	    if (sessionEndTime) timeUpdateFields.sessionEndTime = new Date(sessionEndTime);
397	
398	    let machinesUpdated = 0;
399	    if (Object.keys(timeUpdateFields).length > 0) {
400	      const result = await ReportedMachine.updateMany(
401	        { sessionId },
402	        { $set: timeUpdateFields }
403	      );
404	      if (result.matchedCount === 0) {
405	        return NextResponse.json(
406	          { success: false, error: 'Session not found' },
407	          { status: 404 }
408	        );
409	      }
410	      machinesUpdated = result.modifiedCount;
411	    } else {
412	      const existingCount = await ReportedMachine.countDocuments({ sessionId });
413	      if (existingCount === 0) {
414	        return NextResponse.json(
415	          { success: false, error: 'Session not found' },
416	          { status: 404 }
417	        );
418	      }
419	    }
420	
421	    // ============================================================================
422	    // STEP 4: Upsert financial fields into CollectionSessionV2
423	    // ============================================================================
424	    const financialUpdate: Record<string, unknown> = {};
425	    for (const field of FINANCIAL_FIELDS) {
426	      if (field in body) financialUpdate[field] = body[field];
427	    }
428	
429	    if (Object.keys(financialUpdate).length > 0) {
430	      const firstMachine = await ReportedMachine.findOne({ sessionId })
431	        .select('locationId licencee')
432	        .lean<{ locationId?: string; licencee?: string }>();
433	
434	      await CollectionSessionV2.findOneAndUpdate(
435	        { sessionId },
436	        {
437	          $set: {
438	            ...financialUpdate,
439	            sessionId,
440	            locationId: firstMachine?.locationId ?? '',
441	            licencee: firstMachine?.licencee ?? '',
442	          },
443	        },
444	        { upsert: true }
445	      );
446	    }
447	
448	    if (
449	      Object.keys(timeUpdateFields).length === 0 &&
450	      Object.keys(financialUpdate).length === 0
451	    ) {
452	      return NextResponse.json(
453	        { success: false, error: 'No valid fields to update' },
454	        { status: 400 }
455	      );
456	    }
457	
458	    const duration = Date.now() - startTime;
459	    logRouteUpdate(functionName, 'PATCH', `/api/collection-reports-v2/sessions/${sessionId}`, machinesUpdated, user, duration);
460	
461	    return NextResponse.json({
462	      success: true,
463	      data: {
464	        sessionId,
465	        machinesUpdated,
466	        sessionStartTime: sessionStartTime || undefined,
467	        sessionEndTime: sessionEndTime || undefined,
468	        financialsUpdated: Object.keys(financialUpdate).length > 0,
469	      },
470	    });
471	  } catch (error) {
472	    const errorMessage = error instanceof Error ? error.message : 'Internal server error';
473	    logRouteError(functionName, 'PATCH', `/api/collection-reports-v2/sessions/${sessionId}`, errorMessage, user);
474	    return NextResponse.json({ success: false, error: errorMessage }, { status: 500 });
475	  }
476	}
