30	import { NextRequest, NextResponse } from 'next/server';
31	
32	/**
33	 * PATCH handler for submitting a collection report V2 session.
34	 *
35	 * Flow:
36	 * 1. Connect to database and authenticate user
37	 * 2. Parse request body and validate session ID
38	 * 3. Validate chronological submit (no middle-date insertions)
39	 * 4. Mark session as submitted
40	 * 5. Upload images to Google Drive
41	 * 6. Relocate Drive photos if sasEndTime date changed
42	 * 7. Persist machine meters to Machine document
43	 * 8. Update GamingLocation previousCollectionTime
44	 * 9. Log activity
45	 *
46	 * @param {NextRequest} req - The incoming request
47	 * @param {{ params: Promise<{ sessionId: string }> }} context - Route params containing sessionId
48	 */
49	export async function PATCH(
50	  req: NextRequest,
51	  { params }: { params: Promise<{ sessionId: string }> }
52	) {
53	  const functionName =
54	    'PATCH /api/collection-reports-v2/sessions/[sessionId]/submit';
55	  const user = extractUserFromRequest(req);
56	
57	  let sessionId = '';
58	
59	  try {
60	    // ============================================================================
61	    // STEP 1: Connect to database
62	    // ============================================================================
63	    await connectDB();
64	
65	    // ============================================================================
66	    // STEP 2: Authenticate user
67	    // ============================================================================
68	    const userPayload = await getUserFromServer();
69	    if (!userPayload) {
70	      return NextResponse.json(
71	        { success: false, error: 'Unauthorized' },
72	        { status: 401 }
73	      );
74	    }
75	
76	    // ============================================================================
77	    // STEP 3: Parse request body
78	    // ============================================================================
79	    sessionId = (await params).sessionId;
80	    if (!sessionId) {
81	      return NextResponse.json(
82	        { success: false, error: 'sessionId is required' },
83	        { status: 400 }
84	      );
85	    }
86	
87	    const body = await req.json().catch(() => ({}));
88	    const requestStartTime = body.sessionStartTime as string | undefined;
89	    const frontendImages =
90	      (body.images as
91	        | Array<{
92	            reportedMachineId: string;
93	            imageData: string;
94	            imageCapturedAt?: string;
95	          }>
96	        | undefined) ?? [];
97	    const sessionEndTime = new Date();
98	    const sessionStartTime = requestStartTime
99	      ? new Date(requestStartTime)
100	      : new Date();
101	
102	    // ============================================================================
103	    // STEP 4: Chronological submit check (Middle-Date Block per Machine)
104	    // ============================================================================
105	    const chronologicalError = await validateChronologicalSubmit(
106	      sessionId,
107	      sessionEndTime
108	    );
109	    if (chronologicalError) {
110	      return NextResponse.json(
111	        { success: false, error: chronologicalError },
112	        { status: 400 }
113	      );
114	    }
115	
116	    // ============================================================================
117	    // STEP 5–9: Stream SSE phases while submitting
118	    // Auth, DB, and chronological check are done above.
119	    // ============================================================================
120	    const userInfo = {
121	      _id: userPayload._id as string,
122	      emailAddress: userPayload.emailAddress as string,
123	      roles: userPayload.roles as string[],
124	    };
125	
126	    return createSseResponse(async send => {
127	      // Mark session as submitted
128	      send({ type: 'phase', phase: 'submitting' });
129	      console.log(
130	        `[${functionName}] Submitting session:`,
131	        JSON.stringify(
132	          {
133	            sessionId,
134	            sessionStartTime: sessionStartTime.toISOString(),
135	            sessionEndTime: sessionEndTime.toISOString(),
136	            frontendImagesCount: frontendImages.length,
137	          },
138	          null,
139	          2
140	        )
141	      );
142	
143	      const result = await ReportedMachine.updateMany(
144	        { sessionId },
145	        {
146	          $set: {
147	            sessionStatus: 'submitted',
148	            sessionStartTime,
149	            sessionEndTime,
150	          },
151	        }
152	      );
153	
154	      if (result.matchedCount === 0) {
155	        send({ type: 'error', message: 'Session not found' });
156	        return;
157	      }
158	
159	      // Upload images to Google Drive
160	      send({ type: 'phase', phase: 'uploading' });
161	      const allUploadedImages = await uploadSessionImages(sessionId, frontendImages);
162	
163	      const freshlyUploadedIds = new Set(allUploadedImages.map(img => img.reportedMachineId));
164	      await relocateDrivePhotos(sessionId, freshlyUploadedIds);
165	
166	      // Persist machine meters
167	      send({ type: 'phase', phase: 'persisting' });
168	      const submittedMachines = await ReportedMachine.find(
169	        {
170	          sessionId,
171	          status: { $in: ['captured', 'confirmed'] },
172	        },
173	        'machineId sasMetersIn sasMetersOut sasEndTime locationName locationId prevSasMetersIn prevSasMetersOut manualMetersIn manualMetersOut ramClear ramClearMetersIn ramClearMetersOut isSupplemental'
174	      ).lean<
175	        Array<{
176	          machineId: string;
177	          sasMetersIn: number | null;
178	          sasMetersOut: number | null;
179	          sasEndTime?: Date;
180	          locationName: string;
181	          locationId?: string;
182	          prevSasMetersIn?: number;
183	          prevSasMetersOut?: number;
184	          manualMetersIn?: number;
185	          manualMetersOut?: number;
186	          ramClear?: boolean;
187	          ramClearMetersIn?: number;
188	          ramClearMetersOut?: number;
189	          isSupplemental?: boolean;
190	        }>
191	      >();
192	
193	      if (submittedMachines.length > 0) {
194	        await persistMachineMetersOnSubmit(sessionId, submittedMachines, sessionEndTime);
195	      }
196	
197	      // Backfill reportVersion
198	      send({ type: 'phase', phase: 'backfilling' });
199	      try {
200	        await backfillSessionReportVersion(sessionId, req, userInfo);
201	      } catch (backfillErr) {
202	        console.error(
203	          `[submit] Backfill reportVersion FAILED for session ${sessionId}:`,
204	          backfillErr instanceof Error ? backfillErr.message : 'Unknown error'
205	        );
206	      }
207	
208	      // Log activity
209	      send({ type: 'phase', phase: 'activity' });
210	      try {
211	        await logSubmitActivity(sessionId, req, userInfo);
212	      } catch (logError) {
213	        console.error('Failed to log collection report V2 submit activity:', logError);
214	      }
215	
216	      send({
217	        type: 'done',
218	        data: {
219	          success: true,
220	          data: {
221	            sessionId,
222	            machinesUpdated: result.modifiedCount,
223	            sessionStartTime: sessionStartTime?.toISOString(),
224	            sessionEndTime: sessionEndTime.toISOString(),
225	          },
226	        },
227	      });
228	    });
229	  } catch (error) {
230	    const errorMessage =
231	      error instanceof Error ? error.message : 'Internal server error';
232	    logRouteError(
233	      functionName,
234	      'PATCH',
235	      `/api/collection-reports-v2/sessions/${sessionId}/submit`,
236	      errorMessage,
237	      user
238	    );
239	    return NextResponse.json(
240	      { success: false, error: errorMessage },
241	      { status: 500 }
242	    );
243	  }
244	}
