199	  const user = extractUserFromRequest(req);
200	
201	  try {
202	    // ============================================================================
203	    // STEP 1: Connect to database
204	    // ============================================================================
205	    await connectDB();
206	
207	    // ============================================================================
208	    // STEP 2: Authenticate user
209	    // ============================================================================
210	    const userPayload = await getUserFromServer();
211	    if (!userPayload) {
212	      return NextResponse.json(
213	        { success: false, error: 'Unauthorized' },
214	        { status: 401 }
215	      );
216	    }
217	
218	    // ============================================================================
219	    // STEP 3: Parse ID and request body
220	    // ============================================================================
221	    const { searchParams } = new URL(req.url);
222	    const reportedMachineId = searchParams.get('id');
223	    if (!reportedMachineId) {
224	      return NextResponse.json(
225	        { success: false, error: 'id query param is required' },
226	        { status: 400 }
227	      );
228	    }
229	
230	    const body = (await req.json()) as UpdateMachinePayload;
231	
232	    // ============================================================================
233	    // STEP 4: Fetch target document and check chronological validity
234	    // ============================================================================
235	    const targetMachine = await ReportedMachine.findOne({
236	      _id: reportedMachineId,
237	    }).lean<import('@/app/api/lib/models/reportedMachines').ReportedMachineDocument>();
238	    if (!targetMachine) {
239	      return NextResponse.json(
240	        { success: false, error: 'Machine capture not found' },
241	        { status: 404 }
242	      );
243	    }
244	
245	    const chronoError = await checkChronologicalEdit(targetMachine, body);
246	    if (chronoError) {
247	      return NextResponse.json(
248	        { success: false, error: chronoError.error },
249	        { status: chronoError.status }
250	      );
251	    }
252	
253	    // ============================================================================
254	    // STEP 5: Build update data from body
255	    // ============================================================================
256	    const { updateData, unsetData } = buildUpdateDataFromPayload(body);
257	
258	    // Applicable when ramClear toggled off — strip peak fields from $set
259	    if (Object.keys(unsetData).length > 0) {
260	      if ('ramClearMetersIn' in unsetData) delete updateData.ramClearMetersIn;
261	      if ('ramClearMetersOut' in unsetData) delete updateData.ramClearMetersOut;
262	    }
263	
264	    // ============================================================================
265	    // STEP 6: Enforce null SAS for non-relay machines
266	    // ============================================================================
267	    if (targetMachine.machineId) {
268	      await enforceNoRelayNullSas(targetMachine.machineId, updateData);
269	    }
