297	    if (
298	      Object.keys(updateData).length === 0 &&
299	      Object.keys(unsetData).length === 0 &&
300	      !removeImage
301	    ) {
302	      return NextResponse.json(
303	        { success: false, error: 'No valid fields to update' },
304	        { status: 400 }
305	      );
306	    }
