/**
 * MQTT Configuration API Route
 *
 * This route handles fetching MQTT configuration for a specific cabinet.
 * It supports:
 * - Extracting MQTT configuration from machine document
 * - Formatting configuration values for display
 *
 * @module app/api/mqtt/config/route
 */

import { extractMQTTConfig } from '@/app/api/lib/helpers/mqtt';
import { Machine } from '@/app/api/lib/models/machines';
import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
import {
  logRouteFetch,
  logRouteError,
  extractUserFromRequest,
} from '@/app/api/lib/utils/routeLogger';
import { NextRequest, NextResponse } from 'next/server';

/**
 * Main GET handler for fetching MQTT configuration
 *
 * @param {string} cabinetId - REQUIRED. Query param: The MongoDB ID of the cabinet
 *
 * Flow:
 * 1. Parse and validate request parameters
 * 2. Find cabinet by ID
 * 3. Extract MQTT configuration
 * 4. Return MQTT configuration
 */
export async function GET(request: NextRequest) {
  const startTime = Date.now();
  const functionName = 'GET /api/mqtt/config';
  const user = extractUserFromRequest(request);

  return withApiAuth(request, async () => {
    try {
      // ============================================================================
      // STEP 1: Parse and validate request parameters
      // ============================================================================
      const { searchParams } = new URL(request.url);
      const cabinetId = searchParams.get('cabinetId');

      if (!cabinetId) {
        logRouteError(
          functionName,
          'GET',
          '/api/mqtt/config',
          'Cabinet ID is required',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Cabinet ID is required' },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 2: Find cabinet by ID
      // ============================================================================
      const cabinet = await Machine.findOne({ _id: cabinetId });
      if (!cabinet) {
        logRouteError(
          functionName,
          'GET',
          '/api/mqtt/config',
          'Cabinet not found',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Cabinet not found' },
          { status: 404 }
        );
      }

      // ============================================================================
      // STEP 3: Extract MQTT configuration
      // ============================================================================
      const mqttConfig = extractMQTTConfig(cabinet);

      // ============================================================================
      // STEP 4: Return MQTT configuration
      // ============================================================================
      const duration = Date.now() - startTime;
      logRouteFetch(functionName, 'GET', '/api/mqtt/config', 1, user, duration);
      if (duration > 1000) {
        console.warn(`[MQTT Config API] Completed in ${duration}ms`);
      }
      return NextResponse.json({
        success: true,
        data: mqttConfig,
      });
    } catch (error) {
      const duration = Date.now() - startTime;
      const errorMessage =
        error instanceof Error
          ? error.message
          : 'Failed to fetch MQTT configuration';
      logRouteError(functionName, 'GET', '/api/mqtt/config', errorMessage, user);
      console.error(
        `[MQTT Config GET API] Error after ${duration}ms:`,
        errorMessage
      );
      return NextResponse.json(
        { success: false, error: errorMessage },
        { status: 500 }
      );
    }
  });
}

/**
 * SMIB Discovery API Route
 *
 * This route handles discovering all SMIB devices from the database.
 * It supports:
 * - Finding all machines with relayId configured
 * - Determining online/offline status
 * - Including location information
 *
 * @module app/api/mqtt/discover-smibs/route
 */

import { discoverSMIBDevices } from '@/app/api/lib/helpers/smibDiscovery';
import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
import {
  logRouteFetch,
  logRouteError,
  extractUserFromRequest,
} from '@/app/api/lib/utils/routeLogger';
import { NextRequest, NextResponse } from 'next/server';

/**
 * Main GET handler for discovering SMIB devices
 *
 * Flow:
 * 1. Discover SMIB devices
 * 2. Return SMIB device list
 */
export async function GET(request: NextRequest) {
  const startTime = Date.now();
  const functionName = 'GET /api/mqtt/discover-smibs';
  const user = extractUserFromRequest(request);

  return withApiAuth(request, async () => {
    try {
      // ============================================================================
      // STEP 1: Discover SMIB devices
      // ============================================================================
      const result = await discoverSMIBDevices();

      // ============================================================================
      // STEP 2: Return SMIB device list
      // ============================================================================
      const duration = Date.now() - startTime;
      logRouteFetch(
        functionName,
        'GET',
        '/api/mqtt/discover-smibs',
        result.count,
        user,
        duration
      );
      if (duration > 1000) {
        console.warn(`[SMIB Discovery API] Completed in ${duration}ms`);
      }
      return NextResponse.json(result);
    } catch (error) {
      const duration = Date.now() - startTime;
      const errorMessage =
        error instanceof Error ? error.message : 'Unknown error';
      logRouteError(
        functionName,
        'GET',
        '/api/mqtt/discover-smibs',
        errorMessage,
        user
      );
      console.error(
        `[SMIB Discovery API] Error after ${duration}ms:`,
        errorMessage
      );
      return NextResponse.json(
        {
          success: false,
          error: errorMessage,
          smibs: [],
          count: 0,
        },
        { status: 500 }
      );
    }
  });
}

/**
 * Update Machine Config API Route
 *
 * This route handles updating machine SMIB configuration by relayId.
 * It supports:
 * - Finding machine by relayId
 * - Updating SMIB configuration and version
 * - Activity logging
 *
 * @module app/api/mqtt/update-machine-config/route
 */

import {
  calculateChanges,
  logActivity,
} from '@/app/api/lib/helpers/activityLogger';
import {
  buildMachineConfigUpdateFields,
  findMachineByRelayId,
  getLocationName,
  updateMachineConfiguration,
} from '@/app/api/lib/helpers/machineConfig';
import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
import { getClientIP } from '@/lib/utils/ipAddress';
import {
  logRouteError,
  logRouteUpdate,
  extractUserFromRequest,
} from '@/app/api/lib/utils/routeLogger';
import { NextRequest, NextResponse } from 'next/server';

/**
 * Main POST handler for updating machine configuration
 *
 * @body {string} relayId - REQUIRED. The unique relay ID of the machine.
 * @body {Object} smibConfig - REQUIRED. The new SMIB configuration object.
 * @body {string} smibVersion - Optional. The new SMIB firmware version.
 *
 * Flow:
 * 1. Parse and validate request body
 * 2. Find machine by relayId
 * 3. Get location for logging
 * 4. Build update fields
 * 5. Update machine configuration
 * 6. Log activity
 * 7. Return success response
 */
export async function POST(request: NextRequest) {
  const startTime = Date.now();
  const functionName = 'POST /api/mqtt/update-machine-config';
  const user = extractUserFromRequest(request);

  return withApiAuth(request, async () => {
    try {
      // ============================================================================
      // STEP 1: Parse and validate request body
      // ============================================================================
      const body = await request.json();
      const { relayId, smibConfig, smibVersion } = body as {
        relayId?: string;
        smibConfig?: Record<string, unknown>;
        smibVersion?: Record<string, unknown>;
      };

      if (!relayId) {
        return NextResponse.json(
          { success: false, error: 'relayId is required' },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 2: Find machine by relayId
      // ============================================================================
      const machine = await findMachineByRelayId(relayId);
      if (!machine) {
        return NextResponse.json(
          { success: false, error: 'Machine not found with this relayId' },
          { status: 404 }
        );
      }

      // Type assertion for machine document
      const machineDoc = machine as Awaited<
        ReturnType<typeof findMachineByRelayId>
      > & {
        gamingLocation?: unknown;
        _id: { toString: () => string };
        serialNumber?: string;
        game?: string;
        smibConfig?: Record<string, unknown>;
        smibVersion?: Record<string, unknown>;
        toObject?: () => Record<string, unknown>;
      };

      // ============================================================================
      // STEP 3: Get location for logging
      // ============================================================================
      const locationName = await getLocationName(machineDoc.gamingLocation);

      // ============================================================================
      // STEP 4: Build update fields
      // ============================================================================
      const originalMachine = machineDoc.toObject
        ? machineDoc.toObject()
        : JSON.parse(JSON.stringify(machineDoc));
      const updateFields = buildMachineConfigUpdateFields(
        machineDoc,
        smibConfig,
        smibVersion
      );

      // ============================================================================
      // STEP 5: Update machine configuration
      // ============================================================================
      const updatedMachine = await updateMachineConfiguration(
        machineDoc._id.toString(),
        updateFields
      );

      if (!updatedMachine) {
        return NextResponse.json(
          { success: false, error: 'Failed to update machine' },
          { status: 500 }
        );
      }

      // ============================================================================
      // STEP 6: Log activity
      // ============================================================================
      const currentUser = await getUserFromServer();
      if (currentUser && currentUser.emailAddress) {
        try {
          const changes = calculateChanges(originalMachine, updateFields);

          await logActivity({
            action: 'UPDATE',
            details: `Updated SMIB configuration for machine "${
              machineDoc.serialNumber || machineDoc.game || 'Unknown'
            }" (relayId: ${relayId})${
              locationName ? ` in location "${locationName}"` : ''
            }`,
            ipAddress: getClientIP(request) || undefined,
            userAgent: request.headers.get('user-agent') || undefined,
            metadata: {
              userId: currentUser._id as string,
              userEmail: currentUser.emailAddress as string,
              userRole: (currentUser.roles as string[])?.[0] || 'user',
              resource: 'machine',
              resourceId: machineDoc._id.toString(),
              resourceName:
                machineDoc.serialNumber || machineDoc.game || 'Unknown',
              relayId,
              changes,
              source: 'smib-management-tab',
            },
          });
        } catch (logError) {
          console.error('Failed to log activity:', logError);
        }
      }

      // ============================================================================
      // STEP 7: Return success response
      // ============================================================================
      const duration = Date.now() - startTime;
      logRouteUpdate(
        functionName,
        'POST',
        '/api/mqtt/update-machine-config',
        1,
        user,
        duration
      );
      if (duration > 1000) {
        console.warn(`[Update Machine Config API] Completed in ${duration}ms`);
      }

      return NextResponse.json({
        success: true,
        data: updatedMachine,
        machineId: updatedMachine
          ? (updatedMachine as { _id: { toString: () => string } })._id.toString()
          : machineDoc._id.toString(),
      });
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : 'Unknown error';
      logRouteError(
        functionName,
        'POST',
        '/api/mqtt/update-machine-config',
        errorMessage,
        user
      );
      return NextResponse.json(
        {
          success: false,
          error: errorMessage,
        },
        { status: 500 }
      );
    }
  });
}

/**
 * Schedulers API Route
 *
 * This route handles fetching collection schedulers with filtering.
 * It supports:
 * - Licencee filtering
 * - Location filtering
 * - Collector filtering
 * - Status filtering
 * - Date range filtering
 *
 * @module app/api/schedulers/route
 */

import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
import Scheduler from '@/app/api/lib/models/scheduler';
import type { MongoDBQueryValue } from '@/lib/types/common';
import {
  logRouteFetch,
  logRouteError,
  extractUserFromRequest,
} from '@/app/api/lib/utils/routeLogger';
import { NextRequest, NextResponse } from 'next/server';

/**
 * Main GET handler for fetching schedulers
 *
 * @param {string} licencee - Filter by licencee ID or "all"
 * @param {string} location - Filter by location ID or "all"
 * @param {string} collector - Filter by collector user ID or "all"
 * @param {string} status - Filter by scheduler status
 * @param {string} startDate - Range start for scheduler startTime
 * @param {string} endDate - Range end for scheduler startTime
 *
 * Flow:
 * 1. Parse query parameters (licencee, location, collector, status, dates)
 * 2. Build query filters
 * 3. Fetch schedulers from database
 * 4. Return schedulers list
 */
export async function GET(request: NextRequest) {
  const startTime = Date.now();
  const functionName = 'GET /api/schedulers';
  const user = extractUserFromRequest(request);

  return withApiAuth(request, async () => {
    try {
      // ============================================================================
      // STEP 1: Parse query parameters
      // ============================================================================
      const searchParams = request.nextUrl.searchParams;
      const licencee = searchParams.get('licencee');
      const location = searchParams.get('location');
      const collector = searchParams.get('collector');
      const status = searchParams.get('status');
      const startDate = searchParams.get('startDate');
      const endDate = searchParams.get('endDate');

      // ============================================================================
      // STEP 2: Build query filters
      // ============================================================================
      // Always exclude soft-deleted records
      const query: Record<string, MongoDBQueryValue> = {
        deletedAt: { $exists: false },
      };

      if (licencee && licencee.toLowerCase() !== 'all') {
        query.licencee = licencee;
      }

      if (location && location.toLowerCase() !== 'all') {
        query.location = location;
      }

      if (collector && collector.toLowerCase() !== 'all') {
        query.collector = collector;
      }

      if (status && status.toLowerCase() !== 'all') {
        query.status = status;
      }

      // Date range filter
      if (startDate || endDate) {
        query.startTime = {} as Record<string, Date>;
        if (startDate) {
          (query.startTime as Record<string, Date>).$gte = new Date(startDate);
        }
        if (endDate) {
          (query.startTime as Record<string, Date>).$lte = new Date(endDate);
        }
      }

      // ============================================================================
      // STEP 3: Fetch schedulers from database with aggregated names
      // ============================================================================
      const schedulers = await Scheduler.aggregate([
        { $match: query },
        { $sort: { startTime: -1 } },
        // Join with GamingLocations for location name
        {
          $lookup: {
            from: 'gaminglocations',
            localField: 'location',
            foreignField: '_id',
            as: 'locationInfo',
          },
        },
        // Join with Users for collector name
        {
          $lookup: {
            from: 'users',
            localField: 'collector',
            foreignField: '_id',
            as: 'collectorInfo',
          },
        },
        // Join with Users for creator (manager) name
        {
          $lookup: {
            from: 'users',
            localField: 'creator',
            foreignField: '_id',
            as: 'creatorInfo',
          },
        },
        // Project fields to include names
        {
          $addFields: {
            locationName: {
              $ifNull: [{ $arrayElemAt: ['$locationInfo.name', 0] }, '$location'],
            },
            collectorName: {
              $let: {
                vars: { schedulerUser: { $arrayElemAt: ['$collectorInfo', 0] } },
                in: {
                  $cond: {
                    if: {
                      $and: [
                        '$$schedulerUser.profile.firstName',
                        '$$schedulerUser.profile.lastName',
                      ],
                    },
                    then: {
                      $concat: [
                        '$$schedulerUser.profile.firstName',
                        ' ',
                        '$$schedulerUser.profile.lastName',
                      ],
                    },
                    else: { $ifNull: ['$$schedulerUser.username', '$collector'] },
                  },
                },
              },
            },
            creatorName: {
              $let: {
                vars: { schedulerUser: { $arrayElemAt: ['$creatorInfo', 0] } },
                in: {
                  $cond: {
                    if: {
                      $and: [
                        '$$schedulerUser.profile.firstName',
                        '$$schedulerUser.profile.lastName',
                      ],
                    },
                    then: {
                      $concat: [
                        '$$schedulerUser.profile.firstName',
                        ' ',
                        '$$schedulerUser.profile.lastName',
                      ],
                    },
                    else: { $ifNull: ['$$schedulerUser.username', '$creator'] },
                  },
                },
              },
            },
          },
