/**
 * SMIB Meters API Route
 *
 * This route handles requesting meter data from a single SMIB device.
 * It supports:
 * - Requesting meters by relayId
 * - Finding machine by relayId
 * - Sending meter request via MQTT
 * - Activity logging
 *
 * Note: Uses POST instead of GET because:
 * - We're sending a command/action to the SMIB (triggering it to read meters)
 * - This modifies state (SMIB performs a meter read operation)
 * - Not idempotent (each request triggers a new meter read)
 * - Requires request body (relayId) which is more RESTful as POST
 * - The response comes via MQTT/SSE, not as the HTTP response
 *
 * @module app/api/smib/meters/route
 */

import { logActivity } from '@/app/api/lib/helpers/activityLogger';
import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
import { Machine } from '@/app/api/lib/models/machines';
import { mqttService } from '@/app/api/lib/services/mqttService';
import {
  logRouteCreate,
  logRouteError,
  extractUserFromRequest,
} from '@/app/api/lib/utils/routeLogger';
import { getClientIP } from '@/lib/utils/ipAddress';
import { NextRequest, NextResponse } from 'next/server';

/**
 * Main POST handler for requesting SMIB meters
 *
 * @body {string} relayId - REQUIRED. The unique relay ID of the machine to read meters from.
 *
 * Flow:
 * 1. Parse request body
 * 2. Validate relayId
 * 3. Find machine by relayId
 * 4. Check for MQTT callbacks
 * 5. Send meter request via MQTT
 * 6. Log activity
 * 7. Return success response
 */
export async function POST(request: NextRequest) {
  const startTime = Date.now();
  const functionName = 'POST /api/smib/meters';
  const user = extractUserFromRequest(request);

  return withApiAuth(request, async () => {
    try {
      // ============================================================================
      // STEP 1: Parse request body
      // ============================================================================
      const { relayId } = await request.json();

      // ============================================================================
      // STEP 2: Validate relayId
      // ============================================================================
      if (!relayId) {
        return NextResponse.json(
          { success: false, error: 'RelayId is required' },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 3: Find machine by relayId
      // ============================================================================
      const machine = await Machine.findOne({
        $or: [{ relayId }, { smibBoard: relayId }],
      });

      if (!machine) {
        return NextResponse.json(
          { success: false, error: 'Machine not found for this relayId' },
          { status: 404 }
        );
      }

      // ============================================================================
      // STEP 4: Check for MQTT callbacks
      // ============================================================================
      const hasCallbacks = mqttService.hasCallbacksForRelayId(relayId);
      if (!hasCallbacks) {
        console.warn(
          `No callbacks registered for relayId ${relayId} - response may be lost`
        );
      }

      // ============================================================================
      // STEP 5: Send meter request via MQTT
      // ============================================================================
      try {
        await mqttService.requestMeterData(relayId);
      } catch {
        return NextResponse.json(
          { success: false, error: 'Failed to send meter request to SMIB' },
          { status: 500 }
        );
      }

      // ============================================================================
      // STEP 6: Log activity
      // ============================================================================
      const currentUser = await getUserFromServer();
      const clientIP = getClientIP(request);
      if (currentUser) {
        try {
          await logActivity({
            action: 'VIEW',
            details: `Meter data requested from SMIB ${relayId} for machine ${machine.serialNumber || machine._id}`,
            ipAddress: clientIP || undefined,
            userAgent: request.headers.get('user-agent') || undefined,
            userId: currentUser._id as string,
            username: currentUser.username as string,
            metadata: {
              userRole: (currentUser.roles as string[])?.[0] || 'user',
              resource: 'machine',
              resourceId: machine._id.toString(),
              resourceName: machine.serialNumber || machine.game || machine._id,
              relayId,
              requestedAt: new Date().toISOString(),
            },
          });
        } catch (logError) {
          console.error('Failed to log activity:', logError);
        }
      }

      // ============================================================================
      // STEP 7: Return success response
      // ============================================================================
      const duration = Date.now() - startTime;
      logRouteCreate(functionName, 'POST', '/api/smib/meters', 1, user, duration);

      if (duration > 1000) {
        console.warn(`[SMIB Meters API] Completed in ${duration}ms`);
      }
      return NextResponse.json({
        success: true,
        message: 'Meter request sent successfully',
        relayId,
      });
    } catch (error) {
      const duration = Date.now() - startTime;
      const errorMessage =
        error instanceof Error ? error.message : 'Internal server error';
      logRouteError(functionName, 'POST', '/api/smib/meters', errorMessage, user);
      console.error(`[SMIB Meters API] Error after ${duration}ms:`, errorMessage);
      return NextResponse.json(
        { success: false, error: errorMessage },
        { status: 500 }
      );
    }
  });
}

/**
 * SMIB NVS Action API Route
 *
 * This route handles executing NVS clear actions on SAS SMIB devices.
 * It supports:
 * - clear_nvs: Clear all NVS
 * - clear_nvs_meters: Clear NVS meters
 * - clear_nvs_bv: Clear NVS bill validator
 * - clear_nvs_door: Clear NVS door
 * - Sending commands via MQTT
 * - Activity logging
 *
 * @module app/api/smib/nvs-action/route
 */

import { logActivity } from '@/app/api/lib/helpers/activityLogger';
import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
import { mqttService } from '@/app/api/lib/services/mqttService';
import {
  logRouteCreate,
  logRouteError,
  extractUserFromRequest,
} from '@/app/api/lib/utils/routeLogger';
import { getClientIP } from '@/lib/utils/ipAddress';
import { NextRequest, NextResponse } from 'next/server';

/**
 * Main POST handler for executing NVS actions
 *
 * @body {string} relayId - REQUIRED. The unique relay ID of the target SMIB.
 * @body {string} action - REQUIRED. The NVS clear action ('clear_nvs', 'clear_nvs_meters', etc.).
 *
 * Flow:
 * 1. Parse request body
 * 2. Validate relayId and action
 * 3. Send appropriate NVS command via MQTT
 * 4. Log activity
 * 5. Return success response
 */
export async function POST(request: NextRequest) {
  const startTime = Date.now();
  const functionName = 'POST /api/smib/nvs-action';
  const user = extractUserFromRequest(request);

  return withApiAuth(request, async () => {
    try {
      // ============================================================================
      // STEP 1: Parse request body
      // ============================================================================
      const { relayId, action } = await request.json();

      // ============================================================================
      // STEP 2: Validate relayId and action
      // ============================================================================
      if (!relayId) {
        return NextResponse.json(
          { success: false, error: 'RelayId is required' },
          { status: 400 }
        );
      }

      if (!action) {
        return NextResponse.json(
          { success: false, error: 'Action is required' },
          { status: 400 }
        );
      }

      const validActions = [
        'clear_nvs',
        'clear_nvs_meters',
        'clear_nvs_bv',
        'clear_nvs_door',
      ];
      if (!validActions.includes(action)) {
        return NextResponse.json(
          {
            success: false,
            error: `Invalid action. Must be one of: ${validActions.join(', ')}`,
          },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 3: Send appropriate NVS command via MQTT
      // ============================================================================
      try {
        switch (action) {
          case 'clear_nvs':
            await mqttService.sendClearNvs(relayId);
            break;
          case 'clear_nvs_meters':
            await mqttService.sendClearNvsMeters(relayId);
            break;
          case 'clear_nvs_bv':
            await mqttService.sendClearNvsBv(relayId);
            break;
          case 'clear_nvs_door':
            await mqttService.sendClearNvsDoor(relayId);
            break;
          default:
            throw new Error(`Unhandled action: ${action}`);
        }
      } catch {
        return NextResponse.json(
          { success: false, error: `Failed to send ${action} command to SMIB` },
          { status: 500 }
        );
      }

      // ============================================================================
      // STEP 4: Log activity
      // ============================================================================
      const currentUser = await getUserFromServer();
      const clientIP = getClientIP(request);

      if (currentUser && currentUser.emailAddress) {
        try {
          await logActivity({
            userId: currentUser._id as string,
            username: currentUser.emailAddress as string,
            action: 'update',
            details: `${action} command sent to SMIB ${relayId}`,
            ipAddress: clientIP || undefined,
            userAgent: request.headers.get('user-agent') || undefined,
            metadata: {
              resource: 'machine',
              resourceId: relayId,
              resourceName: relayId,
              userEmail: currentUser.emailAddress as string,
              userRole: (currentUser.roles as string[])?.[0] || 'user',
              relayId,
              nvsAction: action,
              executedAt: new Date().toISOString(),
            },
          });
        } catch (logError) {
          console.error('Failed to log activity:', logError);
        }
      }

      // ============================================================================
      // STEP 5: Return success response
      // ============================================================================
      const duration = Date.now() - startTime;
      logRouteCreate(
        functionName,
        'POST',
        '/api/smib/nvs-action',
        1,
        user,
        duration
      );

      if (duration > 1000) {
        console.warn(`[SMIB NVS Action API] Completed in ${duration}ms`);
      }
      return NextResponse.json({
        success: true,
        message: `${action} command sent successfully`,
        relayId,
        action,
      });
    } catch (error) {
      const duration = Date.now() - startTime;
      const errorMessage =
        error instanceof Error ? error.message : 'Internal server error';
      logRouteError(
        functionName,
        'POST',
        '/api/smib/nvs-action',
        errorMessage,
        user
      );
      console.error(
        `[SMIB NVS Action API] Error after ${duration}ms:`,
        errorMessage
      );
      return NextResponse.json(
        { success: false, error: errorMessage },
        { status: 500 }
      );
    }
  });
}

/**
 * SMIB Restart API Route
 *
 * This route handles restarting a single SMIB device.
 * It supports:
 * - Restarting SMIB by relayId
 * - Finding machine by relayId
 * - Sending restart command via MQTT
 * - Activity logging
 *
 * @module app/api/smib/restart/route
 */

import { logActivity } from '@/app/api/lib/helpers/activityLogger';
import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
import { Machine } from '@/app/api/lib/models/machines';
import { mqttService } from '@/app/api/lib/services/mqttService';
import { getClientIP } from '@/lib/utils/ipAddress';
import {
  logRouteCreate,
  logRouteError,
  extractUserFromRequest,
} from '@/app/api/lib/utils/routeLogger';
import { NextRequest, NextResponse } from 'next/server';

/**
 * Main POST handler for restarting a SMIB device
 *
 * @body {string} relayId - REQUIRED. The 12-char hex relay ID of the SMIB to restart
 *
 * Flow:
 * 1. Parse request body
 * 2. Validate relayId
 * 3. Find machine by relayId
 * 4. Send restart command via MQTT
 * 5. Log activity
 * 6. Return success response
 */
export async function POST(request: NextRequest) {
  const startTime = Date.now();
  const functionName = 'POST /api/smib/restart';
  const user = extractUserFromRequest(request);

  return withApiAuth(request, async () => {
    try {
      // ============================================================================
      // STEP 1: Parse request body
      // ============================================================================
      const { relayId } = await request.json();

      // ============================================================================
      // STEP 2: Validate relayId
      // ============================================================================
      if (!relayId) {
        logRouteError(
          functionName,
          'POST',
          '/api/smib/restart',
          'RelayId is required',
          user
        );
        return NextResponse.json(
          { success: false, error: 'RelayId is required' },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 3: Find machine by relayId
      // ============================================================================
      const machine = await Machine.findOne({
        $or: [{ relayId }, { smibBoard: relayId }],
      });

      if (!machine) {
        logRouteError(
          functionName,
          'POST',
          '/api/smib/restart',
          'Machine not found for this relayId',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Machine not found for this relayId' },
          { status: 404 }
        );
      }

      // ============================================================================
      // STEP 4: Send restart command via MQTT
      // ============================================================================
      try {
        await mqttService.restartSmib(relayId);
      } catch {
        logRouteError(
          functionName,
          'POST',
          '/api/smib/restart',
          'Failed to send restart command to SMIB',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Failed to send restart command to SMIB' },
          { status: 500 }
        );
      }

      // ============================================================================
      // STEP 5: Log activity
      // ============================================================================
      const currentUser = await getUserFromServer();
      const clientIP = getClientIP(request);

      if (currentUser && currentUser.emailAddress) {
        try {
          await logActivity({
            action: 'UPDATE',
            details: `Restart command sent to SMIB ${relayId} for machine ${machine.serialNumber || machine._id}`,
            ipAddress: clientIP || undefined,
            userAgent: request.headers.get('user-agent') || undefined,
            metadata: {
              userId: currentUser._id as string,
              userEmail: currentUser.emailAddress as string,
              userRole: (currentUser.roles as string[])?.[0] || 'user',
              resource: 'machine',
              resourceId: machine._id.toString(),
              resourceName: machine.serialNumber || machine.game || machine._id,
              relayId,
              restartedAt: new Date().toISOString(),
            },
          });
        } catch (logError) {
          console.error('Failed to log activity:', logError);
        }
      }

      // ============================================================================
      // STEP 6: Return success response
      // ============================================================================
      const duration = Date.now() - startTime;
      logRouteCreate(
        functionName,
        'POST',
        '/api/smib/restart',
        1,
        user,
        duration
      );
      if (duration > 1000) {
        console.warn(`[SMIB Restart API] Completed in ${duration}ms`);
      }

      return NextResponse.json({
        success: true,
        message: 'Restart command sent successfully',
        relayId,
      });
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : 'Internal server error';
      logRouteError(
        functionName,
        'POST',
        '/api/smib/restart',
        errorMessage,
        user
      );
      return NextResponse.json(
        { success: false, error: errorMessage },
        { status: 500 }
      );
    }
  });
}

