9	
10	import { connectDB } from '@/app/api/lib/middleware/db';
11	import { ReportedMachine } from '@/app/api/lib/models/reportedMachines';
12	import { Machine } from '@/app/api/lib/models/machines';
13	import { determineAllowedLocationIds } from '@/app/api/lib/helpers/collectionReport/queries';
14	import {
15	  extractUserFromRequest,
16	  logRouteFetch,
17	  logRouteCreate,
18	  logRouteError,
19	} from '@/app/api/lib/utils/routeLogger';
20	import { getUserFromServer } from '@/app/api/lib/helpers/users';
21	import { generateMongoId } from '@/lib/utils/id';
22	import type { MachineDocument } from '@/shared/types/models';
23	import { NextRequest, NextResponse } from 'next/server';
24	import type { TimePeriod } from '@/app/api/lib/types';
25	import {
26	  extractUserPayload,
27	  resolveLicenceeParam,
28	  buildSessionSortConfig,
29	  buildDateFilter,
30	  buildSessionListMatchStage,
31	  buildSessionListPipeline,
32	  buildSessionCountPipeline,
33	  lookupPreviousSessionEndTime,
