137	// ============================================================================
138	// POST — Start a new capture session
139	// ============================================================================
140	
141	export async function POST(req: NextRequest) {
142	  const startTime = Date.now();
143	  const functionName = 'POST /api/collection-reports-v2/sessions';
144	  const user = extractUserFromRequest(req);
145	
146	  try {
147	    // ============================================================================
148	    // STEP 1: Connect and authenticate
149	    // ============================================================================
150	    await connectDB();
151	    const userPayload = await getUserFromServer();
152	    if (!userPayload) {
153	      return NextResponse.json(
154	        { success: false, error: 'Unauthorized' },
155	        { status: 401 }
156	      );
157	    }
158	
159	    // ============================================================================
160	    // STEP 2: Parse request body
161	    // ============================================================================
162	    const body = await req.json();
163	    const { locationId, locationName, licencee } = body as {
164	      locationId: string;
165	      locationName: string;
166	      licencee?: string;
167	    };
168	
169	    if (!locationId || !locationName) {
170	      return NextResponse.json(
171	        { success: false, error: 'locationId and locationName are required' },
172	        { status: 400 }
173	      );
174	    }
175	
176	    const collectorUserId = String((userPayload as unknown as Record<string, string>)._id);
177	    const collectorName =
178	      (userPayload as unknown as Record<string, string>).name ||
179	      (userPayload as unknown as Record<string, string>).username ||
180	      collectorUserId;
181	
182	    // ============================================================================
183	    // STEP 3: Determine session timing
184	    // ============================================================================
185	    const sessionEndTime = new Date();
186	    const previousSessionEndTime = await lookupPreviousSessionEndTime(locationId);
187	    const sessionStartTime: Date | null = previousSessionEndTime;
188	
189	    // ============================================================================
190	    // STEP 4: Verify location access
191	    // ============================================================================
192	    const payloadRecord = userPayload as unknown as Record<string, unknown>;
193	    const { roles, assignedLicencees, assignedLocations } = extractUserPayload(payloadRecord);
194	    const allowedLocationIds = await determineAllowedLocationIds(
195	      roles,
196	      assignedLicencees,
197	      assignedLocations
198	    );
199	
200	    if (allowedLocationIds !== 'all' && !allowedLocationIds.includes(locationId)) {
201	      logRouteError(functionName, 'POST', '/api/collection-reports-v2/sessions', 'Location access denied', user);
202	      return NextResponse.json(
203	        { success: false, error: 'Location access denied' },
204	        { status: 403 }
205	      );
206	    }
207	
208	    // ============================================================================
209	    // STEP 5: Fetch and map machines
210	    // ============================================================================
211	    const DELETION_FILTER = {
212	      $or: [{ deletedAt: null }, { deletedAt: { $lt: new Date('2025-01-01') } }],
213	    };
214	
215	    const machines = await Machine.find({
216	      gamingLocation: locationId,
217	      ...DELETION_FILTER,
218	    })
219	      .select('_id machineId serialNumber custom game manufacturer machineName collectionMeters sasMeters collectionTime previousCollectionTime')
220	      .sort({ 'custom.name': 1, _id: 1 })
221	      .lean<MachineDocument[]>();
222	
223	    const sessionId = await generateMongoId();
224	    const machineList = mapMachinesToV2Format(machines);
225	
226	    // ============================================================================
227	    // STEP 6: Look up last collection times per machine
228	    // ============================================================================
229	    const machineIdsList = machines.map(m => String(m._id));
230	    const lastCollectionMap = await lookupLastSessionEndTimes(machineIdsList);
231	
232	    // ============================================================================
233	    // STEP 7: Persist machines as ReportedMachine documents
234	    // ============================================================================
235	    const collectorId = String((userPayload as unknown as Record<string, string>)._id);
236	    const { reportedMachineDocs } = await buildReportedMachineDocs(
237	      machineList,
238	      sessionId,
239	      locationId,
240	      locationName,
241	      licencee || '',
242	      collectorId,
243	      collectorName,
244	      sessionStartTime ?? undefined,
245	      sessionEndTime,
246	      lastCollectionMap
247	    );
248	
249	    const inserted = await ReportedMachine.insertMany(reportedMachineDocs);
250	    const insertedIds = inserted.map(doc => doc._id);
251	
252	    const duration = Date.now() - startTime;
253	    logRouteCreate(functionName, 'POST', '/api/collection-reports-v2/sessions', inserted.length, user, duration);
254	
255	    // ============================================================================
256	    // STEP 8: Return response
257	    // ============================================================================
258	    return NextResponse.json({
259	      success: true,
260	      data: {
261	        sessionId,
262	        locationId,
263	        locationName,
264	        licencee: licencee || '',
265	        collector: collectorId,
266	        collectorName,
267	        machinesTotal: inserted.length,
268	        machines: machineList,
269	        reportedMachineIds: insertedIds,
270	      },
271	    });
272	  } catch (error) {
273	    const errorMessage = error instanceof Error ? error.message : 'Internal server error';
274	    logRouteError(functionName, 'POST', '/api/collection-reports-v2/sessions', errorMessage, user);
275	    return NextResponse.json({ success: false, error: errorMessage }, { status: 500 });
276	  }
277	}
