1	/**
2	 * Top Performers Metrics API Route
3	 *
4	 * This route handles fetching the top performing machine for a specific location.
5	 * It supports:
6	 * - Filtering by location and time period
7	 * - Custom date range support
8	 * - Optional filtering by licencee
9	 * - Aggregating financial and gaming metrics
10	 *
11	 * @module app/api/metrics/top-performers/route
12	 */
13	
14	import { connectDB } from '@/app/api/lib/middleware/db';
15	import { Meters } from '@/app/api/lib/models/meters';
16	import type { TimePeriod } from '@/app/api/lib/types';
17	import { getDatesForTimePeriod } from '@/app/api/lib/utils/dates';
18	// Note: Db type from mongodb not imported to avoid mongoose/mongodb version mismatch
19	import type { PipelineStage } from 'mongoose';
20	import {
21	  logRouteFetch,
22	  logRouteError,
23	  extractUserFromRequest,
24	} from '@/app/api/lib/utils/routeLogger';
25	import { NextRequest, NextResponse } from 'next/server';
26	/**
27	 * Builds aggregation pipeline for top performer
28	 *
29	 * @param locationId - Location ID to filter by
30	 * @param startDate - Start date
31	 * @param endDate - End date
32	 * @param licencee - Optional licencee to filter by
33	 * @returns Aggregation pipeline stages
34	 */
35	function buildTopPerformerPipeline(
36	  locationId: string,
37	  startDate: Date,
38	  endDate: Date,
39	  licencee?: string | null
40	): PipelineStage[] {
41	  const pipeline: PipelineStage[] = [
42	    {
43	      $match: {
44	        location: locationId,
45	        readAt: { $gte: startDate, $lte: endDate },
46	      },
47	    },
48	    {
49	      $lookup: {
50	        from: 'machines',
51	        localField: 'machine',
52	        foreignField: '_id',
53	        as: 'machineDetails',
54	      },
55	    },
56	    {
57	      $unwind: '$machineDetails',
58	    },
59	    {
60	      $lookup: {
61	        from: 'gaminglocations',
62	        localField: 'location',
63	        foreignField: '_id',
64	        as: 'locationDetails',
65	      },
66	    },
67	    {
68	      $unwind: '$locationDetails',
69	    },
70	  ];
71	
72	  if (licencee) {
73	    pipeline.push({
74	      $match: {
75	        $or: [
76	          { 'locationDetails.rel.licencee': licencee },
77	          { 'locationDetails.rel.licencee': licencee },
78	        ],
79	      },
80	    } as PipelineStage);
81	  }
82	
83	  pipeline.push(
84	    {
85	      $group: {
86	        _id: '$machine',
87	        machineName: { $first: '$machineDetails.Custom.name' },
88	        serialNumber: { $first: '$machineDetails.serialNumber' },
89	        revenue: {
90	          $sum: {
91	            $subtract: [
92	              { $ifNull: ['$movement.drop', 0] },
93	              { $ifNull: ['$movement.totalCancelledCredits', 0] },
94	            ],
95	          },
96	        },
97	        drop: { $sum: { $ifNull: ['$movement.drop', 0] } },
98	        cancelledCredits: {
99	          $sum: { $ifNull: ['$movement.totalCancelledCredits', 0] },
100	        },
101	        gamesPlayed: { $sum: { $ifNull: ['$movement.gamesPlayed', 0] } },
102	      },
103	    },
104	    {
105	      $addFields: {
106	        holdPercentage: {
107	          $cond: [
108	            { $gt: ['$drop', 0] },
109	            { $multiply: [{ $divide: ['$revenue', '$drop'] }, 100] },
110	            0,
111	          ],
112	        },
113	      },
114	    },
115	    {
116	      $sort: { revenue: -1 },
117	    },
118	    {
119	      $limit: 1,
120	    },
121	    {
122	      $project: {
123	        _id: 0,
124	        machineId: '$_id',
125	        machineName: {
126	          $cond: [
127	            { $ne: ['$machineName', null] },
128	            '$machineName',
129	            { $concat: ['Machine ', '$serialNumber'] },
130	          ],
131	        },
132	        revenue: '$revenue',
133	        holdPercentage: { $round: ['$holdPercentage', 1] },
134	        drop: '$drop',
135	        cancelledCredits: '$cancelledCredits',
136	        gamesPlayed: '$gamesPlayed',
137	      },
138	    }
139	  );
140	
141	  return pipeline;
142	}
143	
144	/**
145	 * Fetches top performer for a location
146	 *
147	 * @param locationId - Location ID to filter by
148	 * @param timePeriod - Time period
149	 * @param startDateParam - Optional custom start date
150	 * @param endDateParam - Optional custom end date
151	 * @param licencee - Optional licencee to filter by
152	 * @returns Top performer data or null
153	 */
154	async function getTopPerformer(
155	  locationId: string,
156	  timePeriod: TimePeriod,
157	  startDateParam?: string | null,
158	  endDateParam?: string | null,
159	  licencee?: string | null
160	): Promise<unknown | null> {
161	  let startDate: Date | undefined;
162	  let endDate: Date | undefined;
163	
164	  if (startDateParam && endDateParam) {
165	    startDate = new Date(startDateParam);
166	    endDate = new Date(endDateParam);
167	  } else {
168	    const dateRange = getDatesForTimePeriod(timePeriod);
169	    startDate = dateRange.startDate;
170	    endDate = dateRange.endDate;
171	
172	    if (!startDate || !endDate) {
173	      const now = new Date();
174	      endDate = now;
175	      startDate = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
176	    }
177	  }
178	
179	  const pipeline = buildTopPerformerPipeline(
180	    locationId,
181	    startDate!,
182	    endDate!,
183	    licencee
184	  );
185	
186	  // Use cursor for Meters aggregation
187	  const topPerformers: unknown[] = [];
188	  const cursor = Meters.aggregate(pipeline).cursor({ batchSize: 1000 });
189	  for await (const doc of cursor) {
190	    topPerformers.push(doc);
191	  }
192	  return topPerformers[0] || null;
193	}
194	
195	/**
196	 * Main GET handler for fetching top performer
197	 *
198	 * @param {string} locationId - ID of the location to analyze (REQUIRED)
199	 * @param {string} timePeriod - Time range preset for top performer check
200	 * @param {string} licencee - Filter by licencee name
201	 * @param {string} startDate - ISO date for custom range start
202	 * @param {string} endDate - ISO date for custom range end
203	 *
204	 * Flow:
205	 * 1. Parse and validate request parameters
206	 * 2. Connect to database
207	 * 3. Fetch top performer data
208	 * 4. Return top performer
209	 */
210	export async function GET(req: NextRequest) {
211	  const startTime = Date.now();
212	  const functionName = 'GET /api/metrics/top-performers';
213	  const user = extractUserFromRequest(req);
214	
215	  try {
216	    // ============================================================================
217	    // STEP 1: Parse and validate request parameters
218	    // ============================================================================
219	    const { searchParams } = new URL(req.url);
220	    const locationId = searchParams.get('locationId');
221	    const timePeriod =
222	      (searchParams.get('timePeriod') as TimePeriod) || 'Today';
223	    const licencee = searchParams.get('licencee');
224	    const startDateParam = searchParams.get('startDate');
225	    const endDateParam = searchParams.get('endDate');
226	
227	    if (!locationId) {
228	      logRouteError(
229	        functionName,
230	        'GET',
231	        '/api/metrics/top-performers',
232	        'Location ID is required',
233	        user
234	      );
235	      return NextResponse.json(
236	        { error: 'Location ID is required' },
237	        { status: 400 }
