47	export async function GET(req: NextRequest) {
48	  const startTime = Date.now();
49	  const functionName = 'GET /api/metrics/top-performing';
50	  const user = extractUserFromRequest(req);
51	
52	  try {
53	    // ============================================================================
54	    // STEP 1: Parse and validate request parameters
55	    // ============================================================================
56	    const searchParams = req.nextUrl.searchParams;
57	    const activeTab =
58	      (searchParams.get('activeTab') as TopPerformingTab) || 'locations';
59	    const timePeriod: TimePeriod =
60	      (searchParams.get('timePeriod') as TimePeriod) || '7d';
61	
62	    // Raw licencee from query (name, id, or "all")
63	    const rawLicencee = searchParams.get('licencee') || null;
64	
65	    // Normalize licencee for DB filtering:
66	    // - Resolve known names (TTG, Cabana, etc.) → ID
67	    // - Treat "all" / empty as undefined (no filter)
68	    let licenceeForFilter: string | undefined;
69	    if (rawLicencee && rawLicencee !== 'all') {
70	      licenceeForFilter = resolveLicenceeId(rawLicencee) || rawLicencee;
71	    }
72	
73	    const currencyParam = searchParams.get('currency') as CurrencyCode | null;
74	    const displayCurrency: CurrencyCode = currencyParam || 'USD';
75	
76	    // Parse custom date range for Custom time period
77	    const startDateParam = searchParams.get('startDate');
78	    const endDateParam = searchParams.get('endDate');
79	    let customStartDate: Date | undefined;
80	    let customEndDate: Date | undefined;
81	
82	    if (timePeriod === 'Custom' && startDateParam && endDateParam) {
83	      customStartDate = new Date(startDateParam);
84	      customEndDate = new Date(endDateParam);
85	
86	      // Validate dates
87	      if (isNaN(customStartDate.getTime()) || isNaN(customEndDate.getTime())) {
