121	  let sessionId = '';
122	
123	  try {
124	    // ============================================================================
125	    // STEP 1: Connect and authenticate
126	    // ============================================================================
127	    await connectDB();
128	    const userPayload = await getUserFromServer();
129	    if (!userPayload) {
130	      return NextResponse.json(
131	        { success: false, error: 'Unauthorized' },
132	        { status: 401 }
133	      );
134	    }
135	
136	    // ============================================================================
137	    // STEP 2: Parse session ID
138	    // ============================================================================
139	    sessionId = (await params).sessionId;
140	    if (!sessionId) {
141	      return NextResponse.json(
142	        { success: false, error: 'sessionId is required' },
143	        { status: 400 }
144	      );
145	    }
146	
147	    // ============================================================================
148	    // STEP 3: Fetch session machines
149	    // ============================================================================
150	    const sessionMatch: Record<string, unknown> = { sessionId };
151	    sessionMatch.$or = [{ deletedAt: null }, { deletedAt: { $exists: false } }];
152	
153	    const machines = await ReportedMachine.find(sessionMatch)
154	      .sort({ sequenceOrder: 1 })
155	      .lean<ReportedMachineDocument[]>();
156	
157	    if (machines.length === 0) {
158	      return NextResponse.json(
159	        { success: false, error: 'Session not found' },
160	        { status: 404 }
161	      );
162	    }
163	
164	    // ============================================================================
165	    // STEP 4: Verify location access
166	    // ============================================================================
167	    const sessionLocationId = machines[0].locationId;
168	    const { roles, assignedLicencees, assignedLocations } = extractUserPayload(
169	      userPayload as unknown as Record<string, unknown>
170	    );
171	
172	    const hasAccess = await verifySessionLocationAccess(
173	      sessionLocationId,
174	      roles,
175	      assignedLicencees,
176	      assignedLocations
177	    );
178	
179	    if (!hasAccess) {
180	      logRouteError(functionName, 'GET', `/api/collection-reports-v2/sessions/${sessionId}`, 'Location access denied', user);
181	      return NextResponse.json(
182	        { success: false, error: 'Access denied' },
183	        { status: 403 }
184	      );
185	    }
186	
187	    // ============================================================================
188	    // STEP 5: Build session detail response + fetch financials
189	    // ============================================================================
190	    const [sessionData, rawFinancials] = await Promise.all([
191	      buildSessionDetailResponse(sessionId, machines),
192	      CollectionSessionV2.findOne({ sessionId }).lean<CollectionSessionV2Document>(),
193	    ]);
194	
195	    // ============================================================================
196	    // STEP 6: Apply reviewer scale (no-op for non-reviewer users)
197	    // ============================================================================
198	    const referenceDate = sessionData.sessionEndTime ?? new Date();
199	    const moneyInScale = getMoneyInScale(
200	      userPayload as Parameters<typeof getMoneyInScale>[0],
201	      referenceDate
202	    );
203	    const moneyOutScale = getMoneyOutAndJackpotScale(
204	      userPayload as Parameters<typeof getMoneyOutAndJackpotScale>[0],
205	      referenceDate
206	    );
207	
208	    const scaledMachines = sessionData.machines.map(m =>
209	      applyScaleToMachine(m, moneyInScale, moneyOutScale)
210	    );
211	    const scaledFinancials = applyScaleToFinancials(rawFinancials, moneyInScale, moneyOutScale);
212	
213	    const duration = Date.now() - startTime;
214	    logRouteFetch(functionName, 'GET', `/api/collection-reports-v2/sessions/${sessionId}`, machines.length, user, duration);
215	
216	    return NextResponse.json({
217	      success: true,
218	      data: { ...sessionData, machines: scaledMachines, financials: scaledFinancials },
219	    });
220	  } catch (error) {
221	    const errorMessage = error instanceof Error ? error.message : 'Internal server error';
222	    logRouteError(functionName, 'GET', `/api/collection-reports-v2/sessions/${sessionId}`, errorMessage, user);
223	    return NextResponse.json({ success: false, error: errorMessage }, { status: 500 });
