32	/**
33	 * PATCH handler for submitting a collection report V2 session.
34	 *
35	 * Flow:
36	 * 1. Connect to database and authenticate user
37	 * 2. Parse request body and validate session ID
38	 * 3. Validate chronological submit (no middle-date insertions)
39	 * 4. Mark session as submitted
40	 * 5. Upload images to Google Drive
41	 * 6. Relocate Drive photos if sasEndTime date changed
42	 * 7. Persist machine meters to Machine document
43	 * 8. Update GamingLocation previousCollectionTime
44	 * 9. Log activity
45	 *
46	 * @param {NextRequest} req - The incoming request
47	 * @param {{ params: Promise<{ sessionId: string }> }} context - Route params containing sessionId
48	 */
49	export async function PATCH(
50	  req: NextRequest,
51	  { params }: { params: Promise<{ sessionId: string }> }
52	) {
53	  const functionName =
54	    'PATCH /api/collection-reports-v2/sessions/[sessionId]/submit';
55	  const user = extractUserFromRequest(req);
56	
57	  let sessionId = '';
58	
59	  try {
60	    // ============================================================================
61	    // STEP 1: Connect to database
62	    // ============================================================================
63	    await connectDB();
64	
65	    // ============================================================================
66	    // STEP 2: Authenticate user
67	    // ============================================================================
68	    const userPayload = await getUserFromServer();
69	    if (!userPayload) {
70	      return NextResponse.json(
71	        { success: false, error: 'Unauthorized' },
72	        { status: 401 }
73	      );
74	    }
75	
76	    // ============================================================================
77	    // STEP 3: Parse request body
78	    // ============================================================================
79	    sessionId = (await params).sessionId;
80	    if (!sessionId) {
81	      return NextResponse.json(
82	        { success: false, error: 'sessionId is required' },
83	        { status: 400 }
84	      );
85	    }
86	
87	    const body = await req.json().catch(() => ({}));
88	    const requestStartTime = body.sessionStartTime as string | undefined;
89	    const frontendImages =
90	      (body.images as
91	        | Array<{
92	            reportedMachineId: string;
93	            imageData: string;
94	            imageCapturedAt?: string;
95	          }>
96	        | undefined) ?? [];
97	    const sessionEndTime = new Date();
98	    const sessionStartTime = requestStartTime
99	      ? new Date(requestStartTime)
100	      : new Date();
101	
102	    // ============================================================================
103	    // STEP 4: Chronological submit check (Middle-Date Block per Machine)
104	    // ============================================================================
105	    const chronologicalError = await validateChronologicalSubmit(
106	      sessionId,
107	      sessionEndTime
108	    );
109	    if (chronologicalError) {
110	      return NextResponse.json(
111	        { success: false, error: chronologicalError },
112	        { status: 400 }
113	      );
114	    }
115	
116	    // ============================================================================
117	    // STEP 5–9: Stream SSE phases while submitting
118	    // Auth, DB, and chronological check are done above.
119	    // ============================================================================
120	    const userInfo = {
121	      _id: userPayload._id as string,
122	      emailAddress: userPayload.emailAddress as string,
123	      roles: userPayload.roles as string[],
124	    };
125	
126	    return createSseResponse(async send => {
127	      // Mark session as submitted
128	      send({ type: 'phase', phase: 'submitting' });
129	
130	      const result = await ReportedMachine.updateMany(
131	        { sessionId },
132	        {
133	          $set: {
134	            sessionStatus: 'submitted',
135	            sessionStartTime,
136	            sessionEndTime,
137	          },
138	        }
139	      );
140	
141	      if (result.matchedCount === 0) {
142	        send({ type: 'error', message: 'Session not found' });
143	        return;
144	      }
145	
146	      // Upload images to Google Drive
147	      send({ type: 'phase', phase: 'uploading' });
148	      const allUploadedImages = await uploadSessionImages(sessionId, frontendImages);
149	
150	      const freshlyUploadedIds = new Set(allUploadedImages.map(img => img.reportedMachineId));
151	      await relocateDrivePhotos(sessionId, freshlyUploadedIds);
152	
153	      // Persist machine meters
154	      send({ type: 'phase', phase: 'persisting' });
155	      const submittedMachines = await ReportedMachine.find(
156	        {
157	          sessionId,
158	          status: { $in: ['captured', 'confirmed'] },
159	        },
160	        'machineId sasMetersIn sasMetersOut sasEndTime locationName locationId prevSasMetersIn prevSasMetersOut manualMetersIn manualMetersOut ramClear ramClearMetersIn ramClearMetersOut isSupplemental'
161	      ).lean<
162	        Array<{
163	          machineId: string;
164	          sasMetersIn: number | null;
165	          sasMetersOut: number | null;
166	          sasEndTime?: Date;
167	          locationName: string;
168	          locationId?: string;
169	          prevSasMetersIn?: number;
170	          prevSasMetersOut?: number;
171	          manualMetersIn?: number;
172	          manualMetersOut?: number;
173	          ramClear?: boolean;
174	          ramClearMetersIn?: number;
175	          ramClearMetersOut?: number;
176	          isSupplemental?: boolean;
177	        }>
178	      >();
179	
180	      if (submittedMachines.length > 0) {
181	        await persistMachineMetersOnSubmit(sessionId, submittedMachines, sessionEndTime);
182	      }
183	
184	      // Backfill reportVersion
185	      send({ type: 'phase', phase: 'backfilling' });
186	      try {
187	        await backfillSessionReportVersion(sessionId, req, userInfo);
188	      } catch (backfillErr) {
189	        console.error(
190	          `[submit] Backfill reportVersion FAILED for session ${sessionId}:`,
191	          backfillErr instanceof Error ? backfillErr.message : 'Unknown error'
192	        );
193	      }
194	
195	      // Log activity
196	      send({ type: 'phase', phase: 'activity' });
197	      try {
198	        await logSubmitActivity(sessionId, req, userInfo);
199	      } catch (logError) {
200	        console.error('Failed to log collection report V2 submit activity:', logError);
201	      }
202	
203	      send({
204	        type: 'done',
205	        data: {
206	          success: true,
207	          data: {
208	            sessionId,
209	            machinesUpdated: result.modifiedCount,
210	            sessionStartTime: sessionStartTime?.toISOString(),
211	            sessionEndTime: sessionEndTime.toISOString(),
212	          },
213	        },
214	      });
215	    });
216	  } catch (error) {
217	    const errorMessage =
218	      error instanceof Error ? error.message : 'Internal server error';
219	    logRouteError(
220	      functionName,
221	      'PATCH',
222	      `/api/collection-reports-v2/sessions/${sessionId}/submit`,
223	      errorMessage,
224	      user
225	    );
226	    return NextResponse.json(
227	      { success: false, error: errorMessage },
228	      { status: 500 }
229	    );
230	  }
231	}
