248	        { success: false, error: chronoError.error },
249	        { status: chronoError.status }
250	      );
251	    }
252	
253	    // ============================================================================
254	    // STEP 5: Build update data from body
255	    // ============================================================================
256	    const { updateData, unsetData } = buildUpdateDataFromPayload(body);
257	
258	    // Applicable when ramClear toggled off — strip peak fields from $set
259	    if (Object.keys(unsetData).length > 0) {
260	      if ('ramClearMetersIn' in unsetData) delete updateData.ramClearMetersIn;
261	      if ('ramClearMetersOut' in unsetData) delete updateData.ramClearMetersOut;
262	    }
263	
264	    // ============================================================================
265	    // STEP 6: Enforce null SAS for non-relay machines
266	    // ============================================================================
267	    if (targetMachine.machineId) {
268	      await enforceNoRelayNullSas(targetMachine.machineId, updateData);
269	    }
270	
271	    // ============================================================================
272	    // STEP 7: Handle image updates
273	    // ============================================================================
274	    const removeImage = body.removeImage === true;
275	    await handleImageUpdates(reportedMachineId, body, updateData, removeImage);
276	
277	    // ============================================================================
278	    // STEP 8: Recompute movement if meters, metersMatch, or RAM clear changed
279	    // ============================================================================
280	    if (shouldRecalculateMovement(body)) {
281	      const recalcResult = await resolveAndRecalculateMovement(
282	        reportedMachineId,
283	        body,
284	        updateData
285	      );
286	      if ('error' in recalcResult) {
287	        return NextResponse.json(
288	          { success: false, error: recalcResult.error },
289	          { status: recalcResult.status }
290	        );
291	      }
292	
293	      // Merge recalculated fields into updateData
294	      Object.assign(updateData, recalcResult.data);
295	    }
296	
297	    if (
298	      Object.keys(updateData).length === 0 &&
299	      Object.keys(unsetData).length === 0 &&
300	      !removeImage
301	    ) {
302	      return NextResponse.json(
303	        { success: false, error: 'No valid fields to update' },
304	        { status: 400 }
305	      );
306	    }
307	
308	    // ============================================================================
309	    // STEP 9: Apply MongoDB update
310	    // ============================================================================
311	    const result = await applyMongoUpdate(reportedMachineId, updateData, unsetData);
312	    if (!result) {
313	      return NextResponse.json(
314	        { success: false, error: 'Machine capture not found' },
315	        { status: 404 }
316	      );
317	    }
318	
319	    // ============================================================================
320	    // STEP 10: Cascade to Machine + Meters if session is submitted
321	    // ============================================================================
322	    if (result.sessionStatus === 'submitted') {
323	      handlePostSubmitCascade(result, functionName);
324	    }
325	
326	    // ============================================================================
327	    // STEP 11: Log activity and return response
328	    // ============================================================================
329	    const patchMachineName = String(
330	      result.machineCustomName || result.machineName || reportedMachineId
331	    );
332	    logActivity({
333	      action: 'UPDATE',
334	      details: `Edited machine ${patchMachineName} in V2 session ${result.sessionId}`,
335	      userId: String(userPayload._id),
336	      username: String(userPayload.emailAddress ?? userPayload._id),
337	      metadata: {
338	        userId: String(userPayload._id),
339	        userEmail: String(userPayload.emailAddress ?? ''),
340	        resource: 'collection-report-v2-machine',
341	        resourceId: reportedMachineId,
342	        resourceName: patchMachineName,
343	        changes: Object.entries(updateData).map(([field, newValue]) => ({
344	          field,
345	          oldValue: null,
346	          newValue,
347	        })),
348	      },
349	    }).catch(logError => {
350	      console.error('[PATCH machines] Failed to log activity:', logError instanceof Error ? logError.message : 'Unknown error');
351	    });
352	
353	    const duration = Date.now() - startTime;
354	    logRouteUpdate(
355	      functionName,
356	      'PATCH',
357	      `/api/collection-reports-v2/machines?id=${reportedMachineId}`,
358	      1,
359	      user,
360	      duration
361	    );
362	
363	    return NextResponse.json({ success: true, data: result });
364	  } catch (error) {
365	    const errorMessage =
366	      error instanceof Error ? error.message : 'Internal server error';
367	    logRouteError(functionName, 'PATCH', '/api/collection-reports-v2/machines', errorMessage, user);
368	    return NextResponse.json(
369	      { success: false, error: errorMessage },
370	      { status: 500 }
371	    );
372	  }
373	}
