1	/**
2	 * Collection Report V2 — Image Upload API
3	 *
4	 * POST /api/collection-reports-v2/upload
5	 * Accepts a FormData payload with a machine meter photo and stores it in
6	 * MongoDB GridFS under the `collection_v2_images` bucket.
7	 */
8	
9	import { connectDB } from '@/app/api/lib/middleware/db';
10	import {
11	  extractUserFromRequest,
12	  logRouteCreate,
13	  logRouteError,
14	} from '@/app/api/lib/utils/routeLogger';
15	import { getUserFromServer } from '@/app/api/lib/helpers/users';
16	import { GridFSBucket } from 'mongodb';
17	import { Readable } from 'stream';
18	import { NextRequest, NextResponse } from 'next/server';
19	
20	const BUCKET_NAME = 'collection_v2_images';
21	const MAX_FILE_SIZE = 10 * 1024 * 1024; // 10 MB
22	const ALLOWED_TYPES = [
23	  'image/jpeg',
24	  'image/jpg',
25	  'image/png',
26	  'image/webp',
27	  'image/heic',
28	];
29	
30	export async function POST(req: NextRequest) {
31	  const startTime = Date.now();
32	  const functionName = 'POST /api/collection-reports-v2/upload';
33	  const user = extractUserFromRequest(req);
34	
35	  try {
36	    // ============================================================================
37	    // STEP 1: Connect to database
38	    // ============================================================================
39	    const db = await connectDB();
40	
41	    // ============================================================================
42	    // STEP 2: Authenticate user
43	    // ============================================================================
44	    const userPayload = await getUserFromServer();
45	    if (!userPayload) {
46	      return NextResponse.json(
47	        { success: false, error: 'Unauthorized' },
48	        { status: 401 }
49	      );
50	    }
51	
52	    // ============================================================================
53	    // STEP 3: Parse form data and validate
54	    // ============================================================================
55	    const formData = await req.formData();
56	    const file = formData.get('file') as File | null;
57	    const sessionId = formData.get('sessionId') as string | null;
58	    const machineId = formData.get('machineId') as string | null;
59	
60	    if (!file || file.size === 0) {
61	      return NextResponse.json(
62	        { success: false, error: 'No file provided' },
63	        { status: 400 }
64	      );
65	    }
66	    if (!sessionId || !machineId) {
67	      return NextResponse.json(
68	        { success: false, error: 'sessionId and machineId are required' },
69	        { status: 400 }
70	      );
71	    }
72	    if (!ALLOWED_TYPES.includes(file.type)) {
73	      return NextResponse.json(
74	        {
75	          success: false,
76	          error: 'Invalid file type. Only images are allowed.',
77	        },
78	        { status: 400 }
79	      );
80	    }
81	    if (file.size > MAX_FILE_SIZE) {
82	      return NextResponse.json(
83	        { success: false, error: 'File too large. Maximum 10 MB.' },
84	        { status: 400 }
85	      );
86	    }
87	
88	    // ============================================================================
89	    // STEP 4: Upload file to GridFS
90	    // ============================================================================
91	    const buffer = Buffer.from(await file.arrayBuffer());
92	    const bucket = new GridFSBucket(db, { bucketName: BUCKET_NAME });
93	
94	    const filename = `v2_${sessionId}_${machineId}_${Date.now()}${getExtension(file.name)}`;
95	    const uploadStream = bucket.openUploadStream(filename, {
96	      metadata: {
97	        originalName: file.name,
98	        mimeType: file.type,
99	        size: file.size,
100	        uploadedAt: new Date(),
101	        uploadedBy: String(userPayload._id),
102	        sessionId,
103	        machineId,
104	        context: 'collection_v2_meter_photo',
105	      },
106	    });
107	
108	    await new Promise<void>((resolve, reject) => {
109	      Readable.from(buffer)
110	        .pipe(uploadStream)
111	        .on('error', reject)
112	        .on('finish', resolve);
113	    });
114	
115	    const duration = Date.now() - startTime;
116	    logRouteCreate(
117	      functionName,
118	      'POST',
119	      '/api/collection-reports-v2/upload',
120	      1,
121	      user,
122	      duration
123	    );
124	
125	    // ============================================================================
126	    // STEP 5: Return success response
127	    // ============================================================================
128	    return NextResponse.json({
129	      success: true,
130	      data: {
131	        imageFileId: String(uploadStream.id),
132	        imageName: filename,
133	        imageSize: file.size,
134	      },
135	    });
136	  } catch (error) {
137	    const errorMessage =
138	      error instanceof Error ? error.message : 'Upload failed';
139	    logRouteError(
140	      functionName,
141	      'POST',
142	      '/api/collection-reports-v2/upload',
143	      errorMessage,
144	      user
145	    );
146	    return NextResponse.json(
147	      { success: false, error: errorMessage },
148	      { status: 500 }
149	    );
150	  }
151	}
152	
153	function getExtension(filename: string): string {
154	  const parts = filename.split('.');
155	  return parts.length > 1
156	    ? `.${parts[parts.length - 1].toLowerCase()}`
157	    : '.jpg';
158	}
