1	/**
2	 * Last Collection Time API Route (V2)
3	 *
4	 * Returns the sasEndTime of the most recent submitted collection session
5	 * for a given machine. Used by the V2 session detail page to pre-populate
6	 * chronological boundaries and check for middle-date captures.
7	 *
8	 * GET /api/collection-reports-v2/machines/last-collection-time?machineId=<id>
9	 */
10	
11	import { connectDB } from '@/app/api/lib/middleware/db';
12	import { ReportedMachine } from '@/app/api/lib/models/reportedMachines';
13	import {
14	  createSuccessResponse,
15	  createErrorResponse,
16	} from '@/app/api/lib/utils/apiResponse';
17	import {
18	  logRouteFetch,
19	  logRouteError,
20	  extractUserFromRequest,
21	} from '@/app/api/lib/utils/routeLogger';
22	import type { ReportedMachineDocument } from '@/app/api/lib/models/reportedMachines';
23	import { NextRequest } from 'next/server';
24	
25	export const runtime = 'nodejs';
26	export const dynamic = 'force-dynamic';
27	
28	/**
29	 * Main GET handler for finding the last collection time in V2
30	 *
31	 * @param {string} machineId - REQUIRED. Query param: The MongoDB ID of the machine
32	 */
33	export async function GET(request: NextRequest) {
34	  const startTime = Date.now();
35	  const functionName =
36	    'GET /api/collection-reports-v2/machines/last-collection-time';
37	  const user = extractUserFromRequest(request);
38	
39	  try {
40	    // ============================================================================
41	    // STEP 1: Parse request parameters
42	    // ============================================================================
43	    const { searchParams } = request.nextUrl;
44	    const machineId = searchParams.get('machineId');
45	    const excludeSessionId = searchParams.get('excludeSessionId');
46	
47	    if (!machineId) {
48	      logRouteError(
49	        functionName,
50	        'GET',
51	        '/api/collection-reports-v2/machines/last-collection-time',
52	        'machineId query parameter is required',
53	        user
54	      );
55	      return createErrorResponse('machineId query parameter is required', 400);
56	    }
57	
58	    // ============================================================================
59	    // STEP 2: Connect to database
60	    // ============================================================================
61	    await connectDB();
62	
63	    // ============================================================================
64	    // STEP 3: Find most recent and oldest submitted session machines
65	    // ============================================================================
66	    const baseFilter: Record<string, unknown> = {
67	      machineId,
68	      sessionStatus: 'submitted',
69	      $or: [{ deletedAt: null }, { deletedAt: { $exists: false } }],
70	    };
71	
72	    if (excludeSessionId) {
73	      baseFilter.sessionId = { $ne: excludeSessionId };
74	    }
75	
76	    // Find the most recent submitted collection for this machine,
77	    // ordered by sasEndTime descending so we get the latest gaming period end.
78	    const lastCollection = await ReportedMachine.findOne(baseFilter, {
79	      sasEndTime: 1,
80	      manualMetersIn: 1,
81	      manualMetersOut: 1,
82	    })
83	      .sort({ sasEndTime: -1 })
84	      .lean<ReportedMachineDocument>();
85	
86	    // Find the oldest submitted collection to establish chronological boundaries
87	    const firstCollection = await ReportedMachine.findOne(baseFilter, {
88	      sasEndTime: 1,
89	    })
90	      .sort({ sasEndTime: 1 })
91	      .lean<ReportedMachineDocument>();
92	
93	    let collectionTime: Date | null = lastCollection?.sasEndTime ?? null;
94	    let firstCollectionTime: Date | null = firstCollection?.sasEndTime ?? null;
95	    let metersIn: number | null = lastCollection?.manualMetersIn ?? null;
96	    let metersOut: number | null = lastCollection?.manualMetersOut ?? null;
97	    const hasPreviousCollection = !!lastCollection;
98	
99	    // ============================================================================
100	    // STEP 4: Fallback to machine collectionMeters if no collection found
101	    // ============================================================================
102	    if (!lastCollection) {
103	      const { Machine } = await import('@/app/api/lib/models/machines');
104	      const machine = await Machine.findOne({ _id: machineId })
105	        .select('collectionTime collectionMeters')
106	        .lean<{
107	          collectionTime?: Date;
108	          collectionMeters?: { metersIn?: number; metersOut?: number };
109	        }>();
110	      if (machine) {
111	        collectionTime = machine.collectionTime ?? null;
112	        firstCollectionTime = machine.collectionTime ?? null;
113	        metersIn = machine.collectionMeters?.metersIn ?? null;
114	        metersOut = machine.collectionMeters?.metersOut ?? null;
115	      }
116	    }
117	
118	    // ============================================================================
119	    // STEP 5: Return response
120	    // ============================================================================
121	    const duration = Date.now() - startTime;
122	    logRouteFetch(
123	      functionName,
124	      'GET',
125	      '/api/collection-reports-v2/machines/last-collection-time',
126	      lastCollection ? 1 : 0,
127	      user,
128	      duration
129	    );
130	
131	    return createSuccessResponse(
132	      {
133	        collectionTime,
134	        firstCollectionTime,
135	        metersIn,
136	        metersOut,
137	        hasPreviousCollection,
138	      },
139	      lastCollection
140	        ? 'Last collection time found (V2)'
141	        : 'No previous submitted V2 collection found for this machine'
142	    );
143	  } catch (error) {
144	    const message =
145	      error instanceof Error ? error.message : 'Internal server error';
146	    logRouteError(
147	      functionName,
148	      'GET',
149	      '/api/collection-reports-v2/machines/last-collection-time',
150	      message,
151	      user
152	    );
153	    return createErrorResponse(message, 500);
154	  }
155	}
