252	    const userRoles = (user?.roles as string[]) || [];
253	    if (!user || !userRoles.some((role: string) => MANAGE_ROLES.includes(role))) {
254	      return NextResponse.json(
255	        {
256	          success: false,
257	          error: 'Unauthorized',
258	          message: 'Insufficient permissions',
259	          timestamp: new Date().toISOString(),
