15	
16	export async function GET(req: NextRequest) {
17	  try {
18	    // ============================================================================
19	    // STEP 1: Connect to database
20	    // ============================================================================
21	    await connectDB();
22	
23	    // ============================================================================
24	    // STEP 2: Authenticate user
25	    // ============================================================================
26	    const userPayload = await getUserFromServer();
27	    if (!userPayload) {
28	      return NextResponse.json(
29	        { success: false, error: 'Unauthorized' },
30	        { status: 401 }
31	      );
32	    }
33	
34	    // ============================================================================
35	    // STEP 3: Parse and validate parameters
36	    // ============================================================================
37	    const { searchParams } = new URL(req.url);
38	    const machineId = searchParams.get('machineId');
39	    const startDate = searchParams.get('startDate');
40	    const endDate = searchParams.get('endDate');
41	
42	    if (!machineId || !startDate || !endDate) {
43	      return NextResponse.json(
44	        {
45	          success: false,
46	          error: 'machineId, startDate, and endDate are required',
47	        },
48	        { status: 400 }
49	      );
50	    }
51	
52	    // ============================================================================
53	    // STEP 4: Find the single most recent meter document in the specified range
54	    // ============================================================================
55	    const start = new Date(startDate);
56	    const end = new Date(endDate);
57	
58	    const latestMeter = await Meters.findOne({
59	      machine: machineId,
60	      readAt: { $gte: start, $lte: end },
61	    })
62	      .sort({ readAt: -1 })
63	      .lean<{ drop?: number; totalCancelledCredits?: number }>();
64	
